  `vehicleAreaType` varchar(100) NOT NULL,
  `propertyType` varchar(100) NOT NULL,
  `module` varchar(40) NOT NULL,
  `accessType` varchar(100) NOT NULL,
  `changeMode` varchar(100) NOT NULL,
  `chineseComment` varchar(4096) NOT NULL,
  `englishComment` varchar(4096) NOT NULL,
  `author` varchar(50) NOT NULL,
  `published` tinyint(1) DEFAULT 0,
  `propertyValue` varchar(512) DEFAULT NULL,
  `project` int(11) DEFAULT NULL,
  `createTime` datetime DEFAULT NULL,
  `deprecation` varchar(1024) DEFAULT '',
  `exportable` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`intId`),
  UNIQUE KEY `PropertyIDs_intValue_idx` (`intValue`),
  UNIQUE KEY `PropertyIDs_id_idx` (`id`),
  FULLTEXT KEY `commentsIndex` (`chineseComment`,`englishComment`)
) ENGINE=InnoDB AUTO_INCREMENT=242 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
