INSERT INTO `aaos_propertyids` VALUES (1,286261504,'INFO_VIN','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆的VIN','VIN of vehicle','google',1,'',0,'2024-11-13 17:14:33','',0),(2,286261505,'INFO_MAKE','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆制造商。\r\n<p>此属性传达了车辆的公共品牌名称。','Manufacturer of vehicle.\r\n<p>This property communicates the vehicle\'s public brand name.','google',1,'',0,'2024-11-13 17:14:33','',0),(3,286261506,'INFO_MODEL','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆型号。\r\n<p>此属性传达了车辆的公共型号名称。','Model of vehicle.\r\n<p>This property communicates the vehicle\'s public model name.','google',1,'',0,'2024-11-13 17:14:33','',0),(4,289407235,'INFO_MODEL_YEAR','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','基于Gregorian日历的YYYY格式的车辆年度。','Model year of vehicle in YYYY format based on Gregorian calendar.','google',1,'',0,'2024-11-13 17:14:33','',0),(5,291504388,'INFO_FUEL_CAPACITY','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆在毫升中的燃油容量。\r\n<p>此属性传达了可以存储在\r\n千里人的车辆。该物业将不会用于电动汽车。那是，\r\n如果{@link #info_fuel_type}仅包含{@link FuelType＃eelity}，则此属性不会是\r\n实施的。对于EVS，请参见{@link #info_ev_battery_capacity}。','Fuel capacity of the vehicle in milliliters.\r\n<p>This property communicates the maximum amount of the fuel that can be stored in the\r\nvehicle in milliliters. This property will not be implemented for electric vehicles. That is,\r\nif {@link #INFO_FUEL_TYPE} only contains {@link FuelType#ELECTRIC}, this property will not be\r\nimplemented. For EVs, see {@link #INFO_EV_BATTERY_CAPACITY}.','google',1,'',0,'2024-11-13 17:14:33','',0),(6,289472773,'INFO_FUEL_TYPE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','列出{@link FuelType}车辆可能使用的。\r\n<p> {@link FuelType＃electry}仅在车辆可充电时才包含。\r\n请注意，即使{@link FuelType＃electry}也没有列为燃料\r\n类型，其他EV属性，例如{@link #info_ev_battery_capacity}仍然可以在\r\n车辆。\r\n<p>例如：\r\n<ul>\r\n<li> FHEVS（完全混合电动汽车）将不包括{@link FuelType＃electry}\r\n{@Code Integer []}值。因此{@code info_fuel_type}将被填充：\r\n{{@link FuelType＃lint Pread}}。\r\n<li>另一方面，Phevs（插电式混合动力汽车）可充电，\r\n因此，将在{@code info_fuel_type}\'s {@code中包括{@link FuelType＃electry}\r\n整数[]}值。因此{@code info_fuel_type}将被填充：\r\n{{@link FuelType＃lint Pread}，{@link FuelType＃equication}}。\r\n</ul>','List the {@link FuelType}s the vehicle may use.\r\n<p>{@link FuelType#ELECTRIC} will only be included if the vehicle is plug in rechargeable.\r\nNote that for this reason, even though {@link FuelType#ELECTRIC} is not listed as a fuel\r\ntype, other EV properties such as {@link #INFO_EV_BATTERY_CAPACITY} can still be supported on\r\nthe vehicle.\r\n<p>For example:\r\n<ul>\r\n <li>FHEVs (Fully Hybrid Electric Vehicles) will not include {@link FuelType#ELECTRIC} in its\r\n {@code Integer[]} value. So {@code INFO_FUEL_TYPE} will be populated as such:\r\n { {@link FuelType#UNLEADED} }.\r\n <li>On the other hand, PHEVs (Plug-in Hybrid Electric Vehicles) are plug in rechargeable,\r\n and hence will include {@link FuelType#ELECTRIC} in {@code INFO_FUEL_TYPE}\'s {@code\r\n Integer[]} value. So {@code INFO_FUEL_TYPE} will be populated as such:\r\n { {@link FuelType#UNLEADED}, {@link FuelType#ELECTRIC} }.\r\n</ul>','google',1,'FuelType',0,'2024-11-13 17:14:33','',0),(7,291504390,'INFO_EV_BATTERY_CAPACITY','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','EV或混合动力汽车的名义可用电池容量。\r\n<p>如果EV\r\n或杂交。当车辆是新的时，这是可用的电池容量。这个值可能是\r\n不同于{@link #ev_current_battery_capacity}，因为{@link\r\n#ev_current_battery_capacity}将实时可用电池容量返回\r\n电池老化和温度依赖性等帐户因素。','Nominal usable battery capacity for EV or hybrid vehicle.\r\n<p>Returns the nominal battery capacity in {@link android.car.VehicleUnit#WATT_HOUR}, if EV\r\nor hybrid. This is the usable battery capacity when the vehicle is new. This value might be\r\ndifferent from {@link #EV_CURRENT_BATTERY_CAPACITY} because {@link\r\n#EV_CURRENT_BATTERY_CAPACITY} returns the real-time usable battery capacity taking into\r\naccount factors such as battery aging and temperature dependency.','google',1,'',0,'2024-11-13 17:14:33','',0),(8,289472775,'INFO_EV_CONNECTOR_TYPE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','{@link android.car.hardware.property.evchargingConnectortepe} s的列表可能会使用。\r\n<p>如果车辆有多个充电端口，此属性将返回所有可能\r\n可以在车辆上至少一个充电端口使用的连接器类型。','List of {@link android.car.hardware.property.EvChargingConnectorType}s this vehicle may use.\r\n<p>If the vehicle has multiple charging ports, this property will return all possible\r\nconnector types that can be used by at least one charging port on the vehicle.','google',1,'EvChargingConnectorType',0,'2024-11-13 17:14:33','',0),(9,289407240,'INFO_FUEL_DOOR_LOCATION','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','{@link PortLocationType}燃油门位置。\r\n<p>此属性传达了车辆在车辆上的位置。这个属性\r\n不会为电动汽车实施。也就是说，如果{@link #info_fuel_type}仅\r\n包含{@link FuelType＃electry}，将无法实现此属性。对于电动汽车，请参阅\r\n{@link #info_ev_port_location}或{@link #info_multi_ev_port_locations}。','{@link PortLocationType} for the fuel door location.\r\n<p>This property communicates the location of the fuel door on the vehicle. This property\r\nwill not be implemented for electric vehicles. That is, if {@link #INFO_FUEL_TYPE} only\r\ncontains {@link FuelType#ELECTRIC}, this property will not be implemented. For EVs, see\r\n{@link #INFO_EV_PORT_LOCATION} or {@link #INFO_MULTI_EV_PORT_LOCATIONS}.','google',1,'PortLocationType',0,'2024-11-13 17:14:33','',0),(10,289407241,'INFO_EV_PORT_LOCATION','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','{@link PortLocationType} EV端口位置。\r\n<p>此属性传达了电动汽车上充电端口的位置。如果有\r\n车辆上的多个端口，这将传达启用最快的端口\r\n在车辆上充电。请参阅{@link #info_multi_ev_port_locations}获取所有信息\r\n端口位置。','{@link PortLocationType} for the EV port location.\r\n<p>This property communicates the location of the charging port on the EV. If there are\r\nmultiple ports on the vehicle, this will communicate the port that enables the fastest\r\ncharging on the vehicle. See {@link #INFO_MULTI_EV_PORT_LOCATIONS} to get information on all\r\nport locations.','google',1,'PortLocationType',0,'2024-11-13 17:14:33','',0),(11,289472780,'INFO_MULTI_EV_PORT_LOCATIONS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','列表{@link PortLocationType} s用于多个EV端口位置。','List {@link PortLocationType}s for Multiple EV port locations.','google',1,'PortLocationType',0,'2024-11-13 17:14:33','',0),(12,356516106,'INFO_DRIVER_SEAT','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','驾驶员座位位置。\r\n<p> {@link android.car.hardware.carpropertyConfig＃getAreaids}中列出的唯一区域ID}\r\n{@code info_driver_seat}将为{@code 0}。','Driver\'s seat location.\r\n<p>The only area ID listed in {@link android.car.hardware.CarPropertyConfig#getAreaIds} for\r\n{@code INFO_DRIVER_SEAT} will be {@code 0}.','google',1,'VehicleAreaSeat',0,'2024-11-13 17:14:33','',0),(13,289472779,'INFO_EXTERIOR_DIMENSIONS','VEHICLE_AREA_TYPE_GLOBAL','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆的外部尺寸为毫米。\r\n<p>在{@link carpropertyvalue＃getValue（）} {@code integer []}中定义的外部尺寸：\r\n<ul>\r\n<li>整数[0] =高度\r\n<li>整数[1] =长度\r\n<li>整数[2] =宽度\r\n<li>整数[3] =宽度包括镜子\r\n<li>整数[4] =车轮底座\r\n<li>整数[5] =轨道宽度正面\r\n<li>整数[6] =轨道宽度后部\r\n<li>整数[7] =遏制到遏制直径\r\n</ul>','Vehicle\'s exterior dimensions in millimeters.\r\n<p>Exterior dimensions defined in the {@link CarPropertyValue#getValue()} {@code Integer[]}:\r\n<ul>\r\n <li>Integer[0] = height\r\n <li>Integer[1] = length\r\n <li>Integer[2] = width\r\n <li>Integer[3] = width including mirrors\r\n <li>Integer[4] = wheel base\r\n <li>Integer[5] = track width front\r\n <li>Integer[6] = track width rear\r\n <li>Integer[7] = curb to curb turning diameter\r\n</ul>','google',1,'',0,'2024-11-13 17:14:33','',0),(14,291504644,'PERF_ODOMETER','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','车辆的当前里程表值以公里为单位。','Current odometer value of the vehicle in kilometers.','google',1,'',0,'2024-11-13 17:14:33','',0),(15,291504647,'PERF_VEHICLE_SPEED','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','车辆的速度为每秒米。\r\n<p>车辆向前移动时，{@code perf_vehicle_speed}是正面的\r\n当车辆向后移动时。另外，此值独立于齿轮值（{@link\r\n#current_gear}或{@link #gear_selection}）。例如，如果{@link #gear_selection}是\r\n{@link车辆gear＃gear_neutral}，{@code perf_vehicle_speed}车辆是积极的\r\n向前移动，向后移动时，不移动时为零。','Speed of the vehicle in meters per second.\r\n<p>When the vehicle is moving forward, {@code PERF_VEHICLE_SPEED} is positive and negative\r\nwhen the vehicle is moving backward. Also, this value is independent of gear value ({@link\r\n#CURRENT_GEAR} or {@link #GEAR_SELECTION}). For example, if {@link #GEAR_SELECTION} is\r\n{@link VehicleGear#GEAR_NEUTRAL}, {@code PERF_VEHICLE_SPEED} is positive when the vehicle is\r\nmoving forward, negative when moving backward, and zero when not moving.','google',1,'',0,'2024-11-13 17:14:33','',0),(16,291504648,'PERF_VEHICLE_SPEED_DISPLAY','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','车辆的速度以每秒为单位的显示器进行显示。\r\n<p>某些汽车的速度比实际速度较慢。这是\r\n通常显示在速度表上。','Speed of the vehicle in meters per second for displays.\r\n<p>Some cars display a slightly slower speed than the actual speed. This is\r\nusually displayed on the speedometer.','google',1,'',0,'2024-11-13 17:14:33','',0),(17,291504649,'PERF_STEERING_ANGLE','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','车辆的前自行车模型转向角度。\r\n<p>左为负。\r\n<p>该特性与方向盘的角度无关。这个属性\r\n传达相对于车辆的前轮角度，而不是\r\n方向盘。','Front bicycle model steering angle for vehicle in degrees.\r\n<p>Left is negative.\r\n<p>This property is independent of the angle of the steering wheel. This property\r\ncommunicates the angle of the front wheels with respect to the vehicle, not the angle of the\r\nsteering wheel.','google',1,'',0,'2024-11-13 17:14:33','',0),(18,291504656,'PERF_REAR_STEERING_ANGLE','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','车辆的后自行车模型转向角度。\r\n<p>左为负。\r\n<p>该特性与方向盘的角度无关。这个属性\r\n传达后轮相对于车辆的角度，而不是\r\n方向盘。','Rear bicycle model steering angle for vehicle in degrees.\r\n<p>Left is negative.\r\n<p>This property is independent of the angle of the steering wheel. This property\r\ncommunicates the angle of the rear wheels with respect to the vehicle, not the angle of the\r\nsteering wheel.','google',1,'',0,'2024-11-13 17:14:33','',0),(19,291504897,'ENGINE_COOLANT_TEMP','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','发动机冷却液温度在摄氏剂中。','Temperature of engine coolant in celsius.','google',1,'',0,'2024-11-13 17:14:33','',0),(20,289407747,'ENGINE_OIL_LEVEL','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','发动机油水平。\r\n<p>返回车辆油位状态。请参阅{@code warephoillevel}\r\n{@Code Engine_oil_level}的可能值。','Engine oil level.\r\n<p>Returns the status of the oil level for the vehicle. See {@code VehicleOilLevel} for\r\npossible values for {@code ENGINE_OIL_LEVEL}.','google',1,'VehicleOilLevel',0,'2024-11-13 17:14:33','',0),(21,291504900,'ENGINE_OIL_TEMP','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','发动机油的温度。','Temperature of engine oil in celsius.','google',1,'',0,'2024-11-13 17:14:33','',0),(22,291504901,'ENGINE_RPM','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','发动机RPM。','Engine rpm.','google',1,'',0,'2024-11-13 17:14:33','',0),(23,287310624,'ENGINE_IDLE_AUTO_STOP_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表发动机空闲自动停止的功能。\r\n<p>如果是真的，则车辆可以在不需要时自动关闭发动机，然后\r\n在需要时自动重新启动它。','Represents feature for engine idle automatic stop.\r\n<p>If true, the vehicle may automatically shut off the engine when it is not needed and then\r\nautomatically restart it when needed.','google',1,'',0,'2024-11-13 17:14:33','',0),(24,289407792,'IMPACT_DETECTED','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','检测到影响。\r\n<p>位标志属性，以传达有关是否发生影响的信息\r\n通过{@link所述的车辆侧面\r\nandroid.car.hardware.property.ImpactSensOrlocation}枚举。作为一个flag属性，这个\r\n必要时可以将属性设置为多个枚举值。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个位标记\r\n来自{@link android.car.hardware.property.ImpactSenSorlocation}。','Impact detected.\r\n<p>Bit flag property to relay information on whether an impact has occurred on a particular\r\nside of the vehicle as described through the {@link\r\nandroid.car.hardware.property.ImpactSensorLocation} enum. As a bit flag property, this\r\nproperty can be set to multiple ORed together values of the enum when necessary.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which bit flags\r\nfrom {@link android.car.hardware.property.ImpactSensorLocation} are supported.','google',1,'android.car.hardware.property.ImpactSensorLocation',0,'2024-11-13 17:14:33','',0),(25,290521862,'WHEEL_TICK','VEHICLE_AREA_TYPE_GLOBAL','Long[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','报告车轮滴答。\r\n<p>数组中的第一个元素是重置计数。重置表示\r\n以前的刻度计数与此和未来的tick数不相同。一些\r\n在刻度计数中发生了某种不连续性。\r\n<p>接下来的四个元素代表了单个车轮的刻度\r\n以下顺序：左前，右前，右后，后左，后左。全部\r\n刻度是累积的。车辆时刻度数量增加\r\n向前移动，当车辆反向移动时减小。tick\r\n用户启动车辆时，应重置为0。\r\n<ul>\r\n<li>长[0] =重置计数\r\n<li>长[1] =左前tick\r\n<li>长[2] =前右刻度\r\n<li>长[3] =后右刻度\r\n<li>长[4] =后左滴答\r\n</ul>\r\n<p> configarray用于指示每轮键式值和\r\n支持哪个车轮。每个每轮钉子值是静态的（即不会\r\n根据车轮的状态进行更新）和最佳近似。例如，如果车辆有\r\n多个轮辋/轮胎尺寸选项，每轮式键式值设置为\r\n通常预期的轮辋/轮胎尺寸。配置设置如下：\r\n<ul>\r\n<li> configarray [0]，位[0：3] =支撑的车轮。使用{@link vericleareawheel}。为了\r\n例如，如果所有车轮都得到了支持，则配置[0] = {@link\r\nVERICLEAREAWHEEL＃WHEEL_LEFT_FRONT} |{@link vericlealeawheel＃wheel_right_front} |{@关联\r\nVERICLEAREAWHEEL＃WHEEL_LEFT_REAR} |{@link vericlealeawheel＃wheel_right_rear}\r\n<li> configarray [1] =每个前左车轮刻度的微米\r\n<li> configarray [2] =每个前右轮tick的微米\r\n<li> configarray [3] =每个后右轮tick的微米\r\n<li> configarray [4] =每后轮滴答毫米\r\n</ul>\r\n<p>注意：如果不支持车轮，则其值始终为0。','Reports wheel ticks.\r\n<p>The first element in the array is a reset count.  A reset indicates\r\nprevious tick counts are not comparable with this and future ones.  Some\r\nsort of discontinuity in tick counting has occurred.\r\n<p>The next four elements represent ticks for individual wheels in the\r\nfollowing order: front left, front right, rear right, rear left.  All\r\ntick counts are cumulative.  Tick counts increment when the vehicle\r\nmoves forward, and decrement when vehicles moves in reverse.  The ticks\r\nshould be reset to 0 when the vehicle is started by the user.\r\n<ul>\r\n <li>Long[0] = reset count\r\n <li>Long[1] = front left ticks\r\n <li>Long[2] = front right ticks\r\n <li>Long[3] = rear right ticks\r\n <li>Long[4] = rear left ticks\r\n</ul>\r\n<p>configArray is used to indicate the micrometers-per-wheel-tick values and\r\nwhich wheels are supported. Each micrometers-per-wheel-tick value is static (i.e. will not\r\nupdate based on wheel\'s status) and a best approximation. For example, if a vehicle has\r\nmultiple rim/tire size options, the micrometers-per-wheel-tick values are set to those for\r\nthe typically expected rim/tire size. configArray is set as follows:\r\n<ul>\r\n <li>configArray[0], bits [0:3] = supported wheels. Uses {@link VehicleAreaWheel}. For\r\n example, if all wheels are supported, then configArray[0] = {@link\r\n VehicleAreaWheel#WHEEL_LEFT_FRONT} | {@link VehicleAreaWheel#WHEEL_RIGHT_FRONT} | {@link\r\n VehicleAreaWheel#WHEEL_LEFT_REAR} | {@link VehicleAreaWheel#WHEEL_RIGHT_REAR}\r\n <li>configArray[1] = micrometers per front left wheel tick\r\n <li>configArray[2] = micrometers per front right wheel tick\r\n <li>configArray[3] = micrometers per rear right wheel tick\r\n <li>configArray[4] = micrometers per rear left wheel tick\r\n</ul>\r\n<p>NOTE:  If a wheel is not supported, its value is always 0.','google',1,'',0,'2024-11-13 17:14:33','',0),(26,291504903,'FUEL_LEVEL','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','毫升的燃油水平。\r\n<p>此属性传达了车辆中剩余的当前燃料量\r\n毫升。该物业将不会用于电动汽车。也就是说，如果{@link\r\n#info_fuel_type}仅包含{@link FuelType＃electry}，此属性不会是\r\n实施的。对于电动汽车，请参见{@link #ev_battery_level}。\r\n<p>此属性的值不会超过{@link #info_fuel_capacity}。','Fuel level in milliliters.\r\n<p>This property communicates the current amount of fuel remaining in the vehicle in\r\nmilliliters. This property will not be implemented for electric vehicles. That is, if {@link\r\n#INFO_FUEL_TYPE} only contains {@link FuelType#ELECTRIC}, this property will not be\r\nimplemented. For EVs, see {@link #EV_BATTERY_LEVEL}.\r\n<p>This property\'s value will not exceed {@link #INFO_FUEL_CAPACITY}.','google',1,'',0,'2024-11-13 17:14:33','',0),(27,287310600,'FUEL_DOOR_OPEN','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','燃油门打开。\r\n<p>此属性传达了车辆上的燃油门是否打开。这\r\n电动汽车将不会实施财产。也就是说，如果{@link #info_fuel_type}\r\n仅包含{@link FuelType＃electry}，将不会实现此属性。对于电动汽车，请参阅\r\n{@link #EV_CHARGE_PORT_OPEN}。','Fuel door open.\r\n<p>This property communicates whether the fuel door on the vehicle is open or not. This\r\nproperty will not be implemented for electric vehicles. That is, if {@link #INFO_FUEL_TYPE}\r\nonly contains {@link FuelType#ELECTRIC}, this property will not be implemented. For EVs, see\r\n{@link #EV_CHARGE_PORT_OPEN}.','google',1,'',0,'2024-11-13 17:14:33','',0),(28,291504905,'EV_BATTERY_LEVEL','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','电动电动电池电量。\r\n<p>如果ev或\r\n杂交种。此值不会超过{@link #ev_current_battery_capacity}。计算\r\n电池百分比，使用：\r\n（{@link #ev_battery_level}/{@link #ev_current_battery_capacity}）*100。','EV battery level.\r\n<p>Returns the current battery level in {@link android.car.VehicleUnit#WATT_HOUR}, if EV or\r\nhybrid. This value will not exceed {@link #EV_CURRENT_BATTERY_CAPACITY}. To calculate the\r\nbattery percentage, use:\r\n({@link #EV_BATTERY_LEVEL}/{@link #EV_CURRENT_BATTERY_CAPACITY})*100.','google',1,'',0,'2024-11-13 17:14:33','',0),(29,291504909,'EV_CURRENT_BATTERY_CAPACITY','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电动汽车或混合动力汽车的当前可用电池容量。\r\n<p>在{@link android.car.car.vehicleunit＃watt_hour}中返回电池容量的实际值\r\n如果EV或混合动力。该属性捕获了实时可用电池容量\r\n电池老化和温度依赖性等帐户因素。因此，这个价值可能\r\n与{@link #info_ev_battery_capacity}不同，因为{@link #info_ev_battery_capacity}\r\n从车辆新车时返回标称电池容量。','Current usable battery capacity for EV or hybrid vehicle.\r\n<p>Returns the actual value of battery capacity in {@link android.car.VehicleUnit#WATT_HOUR},\r\nif EV or hybrid. This property captures the real-time usable battery capacity taking into\r\naccount factors such as battery aging and temperature dependency. Therefore, this value might\r\nbe different from {@link #INFO_EV_BATTERY_CAPACITY} because {@link #INFO_EV_BATTERY_CAPACITY}\r\nreturns the nominal battery capacity from when the vehicle was new.','google',1,'',0,'2024-11-13 17:14:33','',0),(30,287310602,'EV_CHARGE_PORT_OPEN','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','EV充电端口打开。\r\n<p>如果车辆有多个充电端口，则该属性将返回\r\n充电端口是打开的。','EV charge port open.\r\n<p>If the vehicle has multiple charging ports, this property will return true if any of the\r\ncharge ports are open.','google',1,'',0,'2024-11-13 17:14:33','',0),(31,287310603,'EV_CHARGE_PORT_CONNECTED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','EV电荷端口连接。\r\n<p>如果车辆有多个充电端口，则该属性将返回\r\n电荷端口已连接。','EV charge port connected.\r\n<p>If the vehicle has multiple charging ports, this property will return true if any of the\r\ncharge ports are connected.','google',1,'',0,'2024-11-13 17:14:33','',0),(32,291504908,'EV_BATTERY_INSTANTANEOUS_CHARGE_RATE','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','EV瞬时充电率为毫瓦。\r\n<p>正速率表明电池正在充电，负率表示电池电池\r\n被排出。','EV instantaneous charge rate in milliwatts.\r\n<p>Positive rate indicates battery is being charged, and Negative rate indicates battery\r\nbeing discharged.','google',1,'',0,'2024-11-13 17:14:33','',0),(33,291504904,'RANGE_REMAINING','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','剩余范围为米。\r\n<p>车辆中所有能源的剩余范围。例如，混合动力汽车\r\n范围将是基于燃料和电池的范围的总和。','Range remaining in meters.\r\n<p>Range remaining accounts for all energy sources in a vehicle.  For example, a hybrid car\'s\r\nrange will be the sum of the ranges based on fuel and battery.','google',1,'',0,'2024-11-13 17:14:33','',0),(34,291504910,'EV_BATTERY_AVERAGE_TEMPERATURE','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','电动电动电气电池平均温度\r\n<p>在电动汽车中暴露电池的温度。如果电动汽车中存在多个电池，或者\r\n存在多个温度传感器，该属性将设置为有意义的加权\r\n最好的平均代表电池系统的整体温度。','EV battery average temperature\r\n<p>Exposes the temperature of the battery in an EV. If multiple batteries exist in the EV, or\r\nmultiple temperature sensors exist, this property will be set to a meaningful weighted\r\naverage that best represents the overall temperature of the battery system.','google',1,'',0,'2024-11-13 17:14:33','',0),(35,392168201,'TIRE_PRESSURE','VEHICLE_AREA_TYPE_WHEEL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','轮胎压力为千骨。\r\n<p>对于{@link android.car.hardware.carpropertyconfig＃getAreaids}中列出的每个区域ID}\r\n对应{@link android.car.hardware.property.areaidConfig＃getMinvalue（）} and {@link\r\nandroid.car.hardware.property.areaidConfig＃getMaxvalue（）}指示OEM推荐的轮胎\r\n该轮胎的压力范围。','Tire pressure in kilopascals.\r\n<p>For each area ID listed in {@link android.car.hardware.CarPropertyConfig#getAreaIds}, the\r\ncorresponding {@link android.car.hardware.property.AreaIdConfig#getMinValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the OEM recommended tire\r\npressure range for that tire.','google',1,'',0,'2024-11-13 17:14:33','',0),(36,392168202,'CRITICALLY_LOW_TIRE_PRESSURE','VEHICLE_AREA_TYPE_WHEEL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','严重的轮胎压力较低。\r\n<p>对于{@link android.car.hardware.carpropertyconfig＃getAreaids}中列出的每个区域ID}\r\n对应{@code crially_low_tire_pressure}将小于或等于{@link\r\nandroid.car.hardware.property.areaidconfig＃getminvalue（）} {@link #tire_pressure}\r\n同一区域ID。','Critically low tire pressure.\r\n<p>For each area ID listed in {@link android.car.hardware.CarPropertyConfig#getAreaIds}, the\r\ncorresponding {@code CRITICALLY_LOW_TIRE_PRESSURE} will be less than or equal the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} of {@link #TIRE_PRESSURE} for the\r\nsame area ID.','google',1,'',0,'2024-11-13 17:14:33','',0),(37,289408000,'GEAR_SELECTION','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','当前由用户选择的装备。\r\n<p>有关齿轮值枚举，请参见{@link车辆箱}。\r\n<p> Configarray表示车辆支撑齿轮的列表。例如，\r\nEV车辆的配置设置如下：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [1] = {@link车辆gear＃gear_park}\r\n<li> configarray [2] = {@link车辆gear＃gear_drive}\r\n</ul>\r\n<p>示例自动传输配置：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_neutral}\r\n<li> configarray [1] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [2] = {@link车辆gear＃gear_park}\r\n<li> configarray [3] = {@link车辆gear＃gear_drive}\r\n<li> configarray [4] = {@link车辆gear＃gear_first}\r\n<li> configarray [5] = {@link车辆gear＃gear_second}\r\n<li> ...\r\n</ul>\r\n<p>示例手动传输配置：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_neutral}\r\n<li> configarray [1] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [4] = {@link车辆gear＃gear_first}\r\n<li> configarray [5] = {@link车辆gear＃gear_second}\r\n<li> ...\r\n</ul>','Currently selected gear by user.\r\n<p> See {@link VehicleGear} for gear value enum.\r\n<p>configArray represents the list of supported gears for the vehicle. For example,\r\nconfigArray for an EV vehicle is set as follows:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_PARK}\r\n <li>configArray[2] = {@link VehicleGear#GEAR_DRIVE}\r\n</ul>\r\n<p>Example automatic transmission configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_NEUTRAL}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[2] = {@link VehicleGear#GEAR_PARK}\r\n <li>configArray[3] = {@link VehicleGear#GEAR_DRIVE}\r\n <li>configArray[4] = {@link VehicleGear#GEAR_FIRST}\r\n <li>configArray[5] = {@link VehicleGear#GEAR_SECOND}\r\n <li>...\r\n</ul>\r\n<p>Example manual transmission configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_NEUTRAL}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[4] = {@link VehicleGear#GEAR_FIRST}\r\n <li>configArray[5] = {@link VehicleGear#GEAR_SECOND}\r\n <li>...\r\n</ul>','google',1,'VehicleGear',0,'2024-11-13 17:14:33','',0),(38,289408001,'CURRENT_GEAR','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车辆传输的电流{@link车辆箱}。\r\n<p> {@code current_gear}的值可能与{@link的值不匹配\r\n车辆propertyids＃gear_selection}。例如，如果{@link\r\n车辆propertyids＃gear_selection}是{@link车辆＃gear_drive}在带有一个的车辆中\r\n自动变速箱，{@code current_gear}将是{@link之一\r\n车辆柜＃gear_first}，{@link车辆gear＃gear_second}等，它反映了实际装备\r\n传输目前正在运行。\r\n<p> configarray表示{@code\r\nCurrent_gear}。例如，将电动汽车的配置设置为如下：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [1] = {@link车辆gear＃gear_park}\r\n<li> configarray [2] = {@link车辆gear＃gear_drive}\r\n</ul>\r\n<p>示例自动传输配置：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_neutral}\r\n<li> configarray [1] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [2] = {@link车辆gear＃gear_park}\r\n<li> configarray [4] = {@link车辆gear＃gear_first}\r\n<li> configarray [5] = {@link车辆gear＃gear_second}\r\n<li> ...\r\n</ul>\r\n<p>示例手动传输配置：\r\n<ul>\r\n<li> configarray [0] = {@link车辆gear＃gear_neutral}\r\n<li> configarray [1] = {@link车辆gear＃gear_reverse}\r\n<li> configarray [4] = {@link车辆gear＃gear_first}\r\n<li> configarray [5] = {@link车辆gear＃gear_second}\r\n<li> ...\r\n</ul>','Vehicle transmission\'s current {@link VehicleGear}.\r\n<p>{@code CURRENT_GEAR}\'s value may not match that of {@link\r\nVehiclePropertyIds#GEAR_SELECTION}. For example, if the {@link\r\nVehiclePropertyIds#GEAR_SELECTION} is {@link VehicleGear#GEAR_DRIVE} in a vehicle with an\r\nautomatic transmission, the {@code CURRENT_GEAR} will be one of {@link\r\nVehicleGear#GEAR_FIRST}, {@link VehicleGear#GEAR_SECOND}, etc, which reflects the actual gear\r\nthe transmission is currently running in.\r\n<p>configArray represents the list of supported {@link VehicleGear}s for {@code\r\nCURRENT_GEAR}. For example, the configArray for an EV vehicle is set as follows:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_PARK}\r\n <li>configArray[2] = {@link VehicleGear#GEAR_DRIVE}\r\n</ul>\r\n<p>Example automatic transmission configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_NEUTRAL}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[2] = {@link VehicleGear#GEAR_PARK}\r\n <li>configArray[4] = {@link VehicleGear#GEAR_FIRST}\r\n <li>configArray[5] = {@link VehicleGear#GEAR_SECOND}\r\n <li>...\r\n</ul>\r\n<p>Example manual transmission configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleGear#GEAR_NEUTRAL}\r\n <li>configArray[1] = {@link VehicleGear#GEAR_REVERSE}\r\n <li>configArray[4] = {@link VehicleGear#GEAR_FIRST}\r\n <li>configArray[5] = {@link VehicleGear#GEAR_SECOND}\r\n <li>...\r\n</ul>','google',1,'VehicleGear',0,'2024-11-13 17:14:33','',0),(39,287310850,'PARKING_BRAKE_ON','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','停车刹车州。\r\n<p> {@code Parking_brake_on}是真的，表明汽车的停车制动器目前为\r\n已订婚的。错误意味着汽车的停车制动器目前已脱离。','Parking brake state.\r\n<p>{@code PARKING_BRAKE_ON} is true indicates that the car\'s parking brake is currently\r\nengaged. False implies that the car\'s parking brake is currently disengaged.','google',1,'',0,'2024-11-13 17:14:33','',0),(40,287310851,'PARKING_BRAKE_AUTO_APPLY','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','自动停车制动器。\r\n<p> {@code Parking_brake_auto_apply}是正确的\r\n功能当前已启用。错误表示汽车的自动驻车制动功能\r\n当前被禁用。\r\n<p>此属性通常与{@link #Parking_Brake_on}混淆。区别在于\r\n{@link #Parking_Brake_on}描述实际停车制动器当前是否为ON/OFF，\r\n而{@Code Parking_brake_auto_apply}描述了自动停车的功能是否功能\r\n启用/禁用制动器，并且没有描述实际停车的当前状态\r\n制动。','Auto-apply parking brake.\r\n<p>{@code PARKING_BRAKE_AUTO_APPLY} is true indicates that the car\'s automatic parking brake\r\nfeature is currently enabled. False indicates that the car\'s automatic parking brake feature\r\nis currently disabled.\r\n<p>This property is often confused with {@link #PARKING_BRAKE_ON}. The difference is that\r\n{@link #PARKING_BRAKE_ON} describes whether the actual parking brake is currently on/off,\r\nwhereas {@code PARKING_BRAKE_AUTO_APPLY} describes whether the feature of automatic parking\r\nbrake is enabled/disabled, and does not describe the current state of the actual parking\r\nbrake.','google',1,'',0,'2024-11-13 17:14:33','',0),(41,289408012,'EV_BRAKE_REGENERATION_LEVEL','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电子车辆的再生制动水平。\r\n<p>返回再生制动水平的当前设置。较大的设置值是指\r\n从制动中获得更多能量，而较小的设置值则意味着能量较少\r\n从制动中再生。0表示没有再生制动的设置。请参阅{@link\r\nandroid.car.hardware.property.areaidConfig＃getmaxvalue（）}} and {@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}对于可能的值范围。','Regenerative braking level of an electronic vehicle.\r\n<p>Returns the current setting for the regenerative braking level. Larger setting values mean\r\nmore energy regenerated from braking while smaller setting values mean less energy\r\nregenerated from braking. 0 means the setting for no regenerative braking. See {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible values.','google',1,'',0,'2024-11-13 17:14:33','',0),(42,289408013,'EV_STOPPING_MODE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表车辆当前停车模式的属性。\r\n<p>对于全球区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getsupportedenumvalues（）}从{@link获得\r\nandroid.car.hardware.carpropertyconfig＃getAreAidConfig（int）}指定从\r\n{@code evstoppingmode}得到了支持。{@code evstoppingmode}可以扩展到包括更多\r\n未来的国家。','Represents property for the current stopping mode of the vehicle.\r\n<p>For the global area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} obtained from {@link\r\nandroid.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum values from\r\n{@code EvStoppingMode} are supported. {@code EvStoppingMode} may be extended to include more\r\nstates in the future.','google',1,'EvStoppingMode',0,'2024-11-13 17:14:33','',0),(43,287310853,'FUEL_LEVEL_LOW','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','警告燃料低水平。\r\n<p> {@代码fuel_level_low}对应于仪表板上的低燃料警告。一次{@code\r\n设置了fuel_level_low}，直到将更多的燃料添加到车辆中为止。\r\n该物业可能会考虑到车辆的所有燃料来源 - 例如：\r\n<ul>\r\n<li>对于汽油驱动车辆，该特性仅基于气体水平。\r\n<li>对于电池供电的车辆，此属性仅基于电池电量。\r\n<li>对于混合动力汽车，该特性可能基于气体和\r\n电池水平，由OEM自行决定。\r\n</ul>','Warning for fuel low level.\r\n<p>{@code FUEL_LEVEL_LOW} corresponds to the low fuel warning on the dashboard. Once {@code\r\nFUEL_LEVEL_LOW} is set, it should not be cleared until more fuel is added to the vehicle.\r\nThis property may take into account all fuel sources for a vehicle - for example:\r\n<ul>\r\n <li>For a gas powered vehicle, this property is based solely on gas level.\r\n <li>For a battery powered vehicle, this property is based solely on battery level.\r\n <li>For a hybrid vehicle, this property may be based on the combination of gas and\r\n battery levels, at the OEM\'s discretion.\r\n</ul>','google',1,'',0,'2024-11-13 17:14:33','',0),(44,287310855,'NIGHT_MODE','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','夜间模式。\r\n<p> true表示夜间模式传感器已检测到汽车舱环境\r\n低光。','Night mode.\r\n<p>True indicates that the night mode sensor has detected that the car cabin environment has\r\nlow light.','google',1,'',0,'2024-11-13 17:14:33','',0),(45,289408008,'TURN_SIGNAL_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车辆的状态转动信号\r\n<p>有关{@code turn_signal_state}的可能值，请参见{@Code vearicleturnsignal}。','State of the vehicles turn signals\r\n<p>See {@code VehicleTurnSignal} for possible values for {@code TURN_SIGNAL_STATE}.','google',1,'VehicleTurnSignal',0,'2024-11-13 17:14:33','',0),(46,289408009,'IGNITION_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车辆的点火状态。\r\n<p>有关{@Code Ignition_state}的可能值，请参见{@link warephignitionState}。','Vehicle\'s ignition state.\r\n<p>See {@link VehicleIgnitionState} for possible values for {@code IGNITION_STATE}.','google',1,'VehicleIgnitionState',0,'2024-11-13 17:14:33','',0),(47,287310858,'ABS_ACTIVE','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','ABS是活跃的。','ABS is active.','google',1,'',0,'2024-11-13 17:14:33','',0),(48,287310859,'TRACTION_CONTROL_ACTIVE','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','牵引力控制是活跃的。','Traction Control is active.','google',1,'',0,'2024-11-13 17:14:33','',0),(49,287310862,'ELECTRONIC_STABILITY_CONTROL_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用电子稳定控制（ESC）。\r\n<p>如果启用ESC，则返回true，如果禁用了ESC，则false。启用ESC时，系统\r\n在车辆中，应控制轮胎在高风险上\r\n积极防止同样的事情发生。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Electronic Stability Control (ESC).\r\n<p>Returns true if ESC is enabled and false if ESC is disabled. When ESC is enabled, a system\r\nin the vehicle should be controlling the tires during instances with high risk of skidding to\r\nactively prevent the same from happening.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(50,289408015,'ELECTRONIC_STABILITY_CONTROL_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电子稳定控制（ESC）状态。\r\n<p>返回ESC的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.electRonicStociateControlState}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.electRonicStociateControlState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Electronic Stability Control (ESC) state.\r\n<p>Returns the current state of ESC. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.ElectronicStabilityControlState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.ElectronicStabilityControlState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'android.car.hardware.property.ElectronicStabilityControlState|ErrorState',0,'2024-11-13 17:14:33','',0),(51,356517120,'HVAC_FAN_SPEED','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','风扇速度设置。','Fan speed setting.','google',1,'',0,'2024-11-13 17:14:33','',0),(52,356517121,'HVAC_FAN_DIRECTION','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','风扇方向设置。','Fan direction setting.','google',1,'CarHvacFanDirection',0,'2024-11-13 17:14:33','',0),(53,358614274,'HVAC_TEMPERATURE_CURRENT','VEHICLE_AREA_TYPE_SEAT','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','HVAC电流温度在摄氏度中。','HVAC current temperature in celsius.','google',1,'',0,'2024-11-13 17:14:33','',0),(54,358614275,'HVAC_TEMPERATURE_SET','VEHICLE_AREA_TYPE_SEAT','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','HVAC目标温度在摄氏摄氏度中设置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示最小值\r\n摄氏温度设置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}指示最大值\r\n摄氏温度设置。\r\n<p>车辆可能不支持设置之间的连续温度值范围\r\n最小值和最大值。\r\n<p>因此，如果车辆支持{@link #hvac_temperature_value_suggestion}，则\r\n应用程序应使用该属性在设置{@code之前获得支持的值\r\nhvac_temperature_set}。该应用程序还应使用{@link\r\n#hvac_temperature_value_suggestion}用于将温度从摄氏转换为华氏\r\n反之亦然。\r\n<p>其他\r\n然后，它表示可以设置的有效温度值列表。它还描述了\r\n查找表可将温度从摄氏转换为华氏度，反之亦然\r\n车辆。\r\n<p> {@code configarray}设置如下：\r\n<ul>\r\n<li> {@code configarray [0]}是[摄氏摄氏温度的下限]\r\n* 10。\r\n<li> {@code configarray [1]}是[摄氏摄氏温度的上限]\r\n* 10。\r\n<li> {@code configarray [2]}是[CELSIUS中的增量] * 10。\r\n<li> {@代码configarray [3]}是\r\n[华氏度温度的下限] * 10。\r\n<li> {@代码configarray [4]}是\r\n[华氏温度中受支持温度的上限] * 10。\r\n<li> {@code configarray [5]}是[华氏度的增量] * 10。\r\n</ul>\r\n<p>例如，如果车辆支持温度值，则为：\r\n<pre>\r\n[16.0，16.5，17.0，...，28.0]\r\n[60.5，61.5，62.5，...，84.5]在华氏\r\n</pre>\r\n<p> {@code configarray}应该是：\r\n<pre>\r\n{@code configarray = {160、280、5、605、845、10}}}\r\n</pre>\r\n<p>如果定义了{@code configarray}，则应用程序不应使用任何其他方法\r\n除了{@link #hvac_temperature_value_suggestion}之外，将温度值转换为\r\n{@Code F =（9/5） * C + 32}的标准单元转换公式。任何不在的值集\r\n在有效值列表中包含的行为不确定，可能会导致\r\n应用程序设置的值和VHAL中设置的值的不一致。\r\n<p>用于将温度从摄氏转换为华氏度的温度使用以下内容：\r\n<pre>\r\n{@代码\r\n//给定的tempc和配置\r\nfloat mintempc = configArray.get（0） / 10f;\r\nfloat deveripincrementcelsius = configArray.get（2） / 10f;\r\nfloat mintempf = configarray.get（3） / 10f;\r\nfloat deveripincrementfahenheit = configarray.get（5） / 10f;\r\n//四舍五入到最接近的增量\r\nint numincrements = Math.Round（（（tempc -mintempc） / demetingincrementcelsius）;\r\nfloat tempf =温度incrementfahenheit * numincrents + mintempf;\r\n}\r\n</pre>\r\n<p>用于将温度从华氏度转换为摄氏摄氏度，使用与上述相同的方法\r\n除了将摄氏值更改为相关的华氏度值。\r\n<p> othwerise，如果{@link #hvac_temperature_value_suggestion}也不是{@code\r\n定义了配置}，应用程序应使用标准单位转换公式\r\n{@Code F =（9/5） * C + 32}。','HVAC target temperature set in Celsius.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the minimum\r\ntemperature setting in Celsius.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the maximum\r\ntemperature setting in Celsius.\r\n<p>The vehicle may not support setting a continuous range of temperature values in between\r\nthe min and max values.\r\n<p>Therefore, if the vehicle supports {@link #HVAC_TEMPERATURE_VALUE_SUGGESTION}, the\r\napplication should use that property to get a supported value before setting {@code\r\nHVAC_TEMPERATURE_SET}. The application should also use {@link\r\n#HVAC_TEMPERATURE_VALUE_SUGGESTION} for converting the temperature from Celsius to Fahrenheit\r\nand vice versa for this vehicle.\r\n<p>Else if the {@link android.car.hardware.CarPropertyConfig#getConfigArray()} is defined,\r\nthen it represents the list of valid temperature values that can be set. It also describes a\r\nlookup table to convert the temperature from Celsius to Fahrenheit and vice versa for this\r\nvehicle.\r\n<p>The {@code configArray} is set as follows:\r\n<ul>\r\n     <li>{@code configArray[0]} is [the lower bound of the supported temperature in Celsius]\r\n     * 10.\r\n     <li>{@code configArray[1]} is [the upper bound of the supported temperature in Celsius]\r\n     * 10.\r\n     <li>{@code configArray[2]} is [the increment in Celsius] * 10.\r\n     <li>{@code configArray[3]} is\r\n     [the lower bound of the supported temperature in Fahrenheit] * 10.\r\n     <li>{@code configArray[4]} is\r\n     [the upper bound of the supported temperature in Fahrenheit] * 10.\r\n     <li>{@code configArray[5]} is [the increment in Fahrenheit] * 10.\r\n</ul>\r\n<p>For example, if the vehicle supports temperature values as:\r\n<pre>\r\n[16.0, 16.5, 17.0 ,..., 28.0] in Celsius\r\n[60.5, 61.5, 62.5 ,..., 84.5] in Fahrenheit\r\n</pre>\r\n<p>The {@code configArray} should be:\r\n<pre>\r\n{@code configArray = {160, 280, 5, 605, 845, 10}}\r\n</pre>\r\n<p>If the {@code configArray} is defined, applications should not use any other method for\r\nconverting temperature values besides {@link #HVAC_TEMPERATURE_VALUE_SUGGESTION}, such as the\r\nstandard unit conversion formula of {@code F = (9/5) * C + 32}. Any value set that is not\r\ncontained within the list of valid values is considered undefined behavior and may result in\r\ninconsistencies in the value set by the application and the value set in the VHAL.\r\n<p>For converting the temperature from Celsius to Fahrenheit use the following:\r\n<pre>\r\n{@code\r\n// Given tempC and configArray\r\nfloat minTempC = configArray.get(0) / 10f;\r\nfloat temperatureIncrementCelsius = configArray.get(2) / 10f;\r\nfloat minTempF = configArray.get(3) / 10f;\r\nfloat temperatureIncrementFahrenheit = configArray.get(5) / 10f;\r\n// Round to the closest increment\r\nint numIncrements = Math.round((tempC - minTempC) / temperatureIncrementCelsius);\r\nfloat tempF = temperatureIncrementFahrenheit * numIncrements + minTempF;\r\n}\r\n</pre>\r\n<p>For converting the temperature from Fahrenheit to Celsius, use the same method as above\r\nexcept changing the Celsius values to the relevant Fahrenheit values.\r\n<p>Othwerise, if neither {@link #HVAC_TEMPERATURE_VALUE_SUGGESTION} nor the {@code\r\nconfigArray} are defined, the application should use the standard unit conversion formula of\r\n{@code F = (9/5) * C + 32}.','google',1,'',0,'2024-11-13 17:14:33','',0),(55,291570965,'HVAC_TEMPERATURE_VALUE_SUGGESTION','VEHICLE_AREA_TYPE_GLOBAL','Float[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','设置HVAC温度的建议值。\r\n<p>实施该属性以帮助应用程序了解最接近的温度\r\n在摄氏或华氏度中的价值。\r\n<ul>\r\n<li> {@code floatValues [0]}是应用程序要设置一个的请求值\r\n温度为。\r\n<li> {@代码floatValues [1]}是{@code floatValues [0]}的单位。它应该是之一\r\n（{@link pheremunit＃celsius}，{@link perhatunit＃fahrenheit}）。\r\n<li> {@code floatValues [2]}是Celsius中建议的值。这个值不是\r\n包括在请求中。\r\n<li> {@code floatValues [3]}是Wahrenheit中建议的值。这个值不是\r\n包括在请求中。\r\n</ul>\r\n<p>应用程序调用\r\n{@link android.car.hardware.property.carpropertymanager＃setProperty（class，class，int，int，int，object）}\r\n具有该值的请求值和单位。OEM需要返回建议的值\r\n在{@code floatValues [2]}和{@code floatValues [3]}中\r\n{@link android.car.hardware.property.carpropertymanager.carpropertyeventcallback}。\r\n<p>例如，当用户使用语音助手将HVAC温度设置为66.2时\r\n华氏。\r\n<p>首先，应用程序将设置此属性，\r\n[66.2，{@link parterunit＃fahrenheit}，0，0]。如果OEM建议在Celsius设置19.0\r\n或66.5在Wahrenheit中以供用户的请求\r\n值[66.2，{@link parterunit＃fahrenheit}，19.0，66.5]。语音助手之后\r\n获取回调，它将通知用户并将HVAC温度设置为建议的值。\r\n<p>另一个示例，应用程序通过\r\n查询{@link parterpropertyids＃hvac_temperature_set}。但是该应用程序想知道\r\n华氏汽车的UI上显示了什么价值。\r\n<p>为此，应用程序将属性设置为\r\n[21，{@link wareyunit＃celsius}，0，0]。如果OEM的建议值为21\r\nCelsius是70华氏度，然后汽车必须生成带有属性值的回调\r\n[21，{@link wareyunit＃celsius}，21.0，70.0]。在这种情况下，应用程序可以知道\r\n该价值为70.0华氏度，在汽车上。','Suggested values for setting HVAC temperature.\r\n<p>Implement the property to help applications understand the closest supported temperature\r\nvalue in Celsius or Fahrenheit.\r\n<ul>\r\n     <li>{@code floatValues[0]} is the requested value that an application wants to set a\r\n     temperature to.\r\n     <li>{@code floatValues[1]} is the unit for {@code floatValues[0]}. It should be one of\r\n     ({@link VehicleUnit#CELSIUS}, {@link VehicleUnit#FAHRENHEIT}).\r\n     <li>{@code floatValues[2]} is the value OEMs suggested in CELSIUS. This value is not\r\n     included in the request.\r\n     <li>{@code floatValues[3]} is the value OEMs suggested in FAHRENHEIT. This value is not\r\n     included in the request.\r\n</ul>\r\n<p>An application calls\r\n{@link android.car.hardware.property.CarPropertyManager#setProperty(Class, int, int, Object)}\r\nwith the requested value and unit for the value. OEMs need to return the suggested values\r\nin {@code floatValues[2]} and {@code floatValues[3]} by\r\n{@link android.car.hardware.property.CarPropertyManager.CarPropertyEventCallback}.\r\n<p>For example, when a user uses the voice assistant to set HVAC temperature to 66.2 in\r\nFahrenheit.\r\n<p>First, an application will set this property with the value\r\n[66.2, {@link VehicleUnit#FAHRENHEIT}, 0, 0]. If OEMs suggest to set 19.0 in Celsius\r\nor 66.5 in Fahrenheit for user\'s request, then car must generate a callback with property\r\nvalue [66.2, {@link VehicleUnit#FAHRENHEIT}, 19.0, 66.5]. After the voice assistant\r\ngets the callback, it will inform the user and set HVAC temperature to the suggested value.\r\n<p>Another example, an application receives 21 Celsius as the current temperature value by\r\nquerying {@link VehiclePropertyIds#HVAC_TEMPERATURE_SET}. But the application wants to know\r\nwhat value is displayed on the car\'s UI in Fahrenheit.\r\n<p>For this, the application sets the property to\r\n[21, {@link VehicleUnit#CELSIUS}, 0, 0]. If the suggested value by the OEM for 21\r\nCelsius is 70 Fahrenheit, then car must generate a callback with property value\r\n[21, {@link VehicleUnit#CELSIUS}, 21.0, 70.0]. In this case, the application can know\r\nthat the value is 70.0 Fahrenheit in the car鈥檚 UI.','google',1,'',0,'2024-11-13 17:14:33','',0),(56,320865540,'HVAC_DEFROSTER','VEHICLE_AREA_TYPE_WINDOW','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','指定窗口的开/关除霜。','On/off defrost for designated window.','google',1,'',0,'2024-11-13 17:14:33','',0),(57,354419973,'HVAC_AC_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','开/关AC用于指定的apeardID。','On/off AC for designated areaId.','google',1,'',0,'2024-11-13 17:14:33','',0),(58,354419974,'HVAC_MAX_AC_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','开/关最大交流。','On/off max AC.','google',1,'',0,'2024-11-13 17:14:33','',0),(59,354419975,'HVAC_MAX_DEFROST_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','开/关最大除霜。','On/off max defrost.','google',1,'',0,'2024-11-13 17:14:33','',0),(60,354419976,'HVAC_RECIRC_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','再循环开/关。','Recirculation on/off.','google',1,'',0,'2024-11-13 17:14:33','',0),(61,354419977,'HVAC_DUAL_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用区域之间的温度耦合。','Enable temperature coupling between areas.','google',1,'',0,'2024-11-13 17:14:33','',0),(62,354419978,'HVAC_AUTO_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','开/关自动模式。','On/off automatic mode.','google',1,'',0,'2024-11-13 17:14:33','',0),(63,356517131,'HVAC_SEAT_TEMPERATURE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅加热/冷却。','Seat heating/cooling.','google',1,'',0,'2024-11-13 17:14:33','',0),(64,339739916,'HVAC_SIDE_MIRROR_HEAT','VEHICLE_AREA_TYPE_MIRROR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','后视镜热。','Side Mirror Heat.','google',1,'',0,'2024-11-13 17:14:33','',0),(65,289408269,'HVAC_STEERING_WHEEL_HEAT','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘加热/冷却。','Steering Wheel Heating/Cooling.','google',1,'',0,'2024-11-13 17:14:33','',0),(66,289408270,'HVAC_TEMPERATURE_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','温度单位用于显示。','Temperature units for display.','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(67,356517135,'HVAC_ACTUAL_FAN_SPEED_RPM','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','实际风扇速度。','Actual fan speed.','google',1,'',0,'2024-11-13 17:14:33','',0),(68,354419984,'HVAC_POWER_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表HVAC的全球力量状态。\r\n<p>将此属性设置为false可能会标记一些控制单个HVAC的属性\r\n功能/子系统到不可用的状态。将此属性设置为True可能会标记一些\r\n控制单个HVAC特征/子系统到可用状态的属性（除非\r\n任何/所有人都无法根据自己的个人优点）。','Represents global power state for HVAC.\r\n<p>Setting this property to false MAY mark some properties that control individual HVAC\r\nfeatures/subsystems to UNAVAILABLE state. Setting this property to true MAY mark some\r\nproperties that control individual HVAC features/subsystems to AVAILABLE state (unless\r\nany/all of them are UNAVAILABLE on their own individual merits).','google',1,'',0,'2024-11-13 17:14:33','',0),(69,356582673,'HVAC_FAN_DIRECTION_AVAILABLE','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','风扇位置可用。','Fan Positions Available.','google',1,'CarHvacFanDirection',0,'2024-11-13 17:14:33','',0),(70,354419986,'HVAC_AUTO_RECIRC_ON','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','自动再循环开/关。','Automatic recirculation on/off.','google',1,'',0,'2024-11-13 17:14:33','',0),(71,356517139,'HVAC_SEAT_VENTILATION','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅通风。','Seat ventilation.','google',1,'',0,'2024-11-13 17:14:33','',0),(72,320865556,'HVAC_ELECTRIC_DEFROSTER_ON','VEHICLE_AREA_TYPE_WINDOW','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电气除粒剂。','ELECTRIC DEFROSTER.','google',1,'',0,'2024-11-13 17:14:33','',0),(73,289408512,'DISTANCE_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','显示距离单元。\r\n<p>指示汽车使用哪个单位向用户显示距离。\r\n<p> configarray表示{@code的支持单元的列表\r\ndistand_display_units}。这是一个示例configarray：\r\n<ul>\r\n<li> configarray [0] = {@link perhateUnit＃meter}\r\n<li> configarray [1] = {@link perhaunit＃kilome}\r\n<li> configarray [2] = {@link perhaunit＃mile}\r\n</ul>','Distance units for display.\r\n<p>Indicates which units the car is using to display distances to the user.\r\n<p>configArray represents the list of supported units for {@code\r\nDISTANCE_DISPLAY_UNITS}. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleUnit#METER}\r\n <li>configArray[1] = {@link VehicleUnit#KILOMETER}\r\n <li>configArray[2] = {@link VehicleUnit#MILE}\r\n</ul>','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(74,289408513,'FUEL_VOLUME_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','燃油量单位用于显示。\r\n<p>指示汽车使用哪个单位向用户显示燃油量。\r\n<p> configarray表示{@code的支持单元的列表\r\nfuel_volume_display_units}。这是一个示例configarray：\r\n<ul>\r\n<li> configarray [0] = {@link perhaunit＃liter}\r\n<li> configarray [1] = {@link perhaunit＃us_gallon}\r\n</ul>','Fuel volume units for display.\r\n<p>Indicates which units the car is using to display fuel volume to the user.\r\n<p>configArray represents the list of supported units for {@code\r\nFUEL_VOLUME_DISPLAY_UNITS}. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleUnit#LITER}\r\n <li>configArray[1] = {@link VehicleUnit#US_GALLON}\r\n</ul>','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(75,289408514,'TIRE_PRESSURE_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','轮胎压力单元显示。\r\n<p>指示汽车使用哪个单位向用户显示轮胎压力。\r\n<p> configarray表示{@code的支持单元的列表\r\ntire_pressure_display_units}。这是一个示例configarray：\r\n<ul>\r\n<li> configarray [0] = {@link perhaunit＃kilopascal}\r\n<li> configarray [1] = {@link perhaunit＃psi}\r\n<li> configarray [2] = {@link perhaunit＃bar}\r\n</ul>','Tire pressure units for display.\r\n<p>Indicates which units the car is using to display tire pressure to the user.\r\n<p>configArray represents the list of supported units for {@code\r\nTIRE_PRESSURE_DISPLAY_UNITS}. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleUnit#KILOPASCAL}\r\n <li>configArray[1] = {@link VehicleUnit#PSI}\r\n <li>configArray[2] = {@link VehicleUnit#BAR}\r\n</ul>','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(76,289408515,'EV_BATTERY_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','EV电池单元用于显示。\r\n<p>指示车辆使用哪个单位向用户显示电动电池信息。\r\n<p> configarray表示{@code的支持单元的列表\r\nev_battery_display_units}。这是一个示例configarray：\r\n<ul>\r\n<li> configArray [0] = {@link perhateUnit＃watt_hour}\r\n<li> configArray [1] = {@link perhaunit＃ampere_hours}\r\n<li> configarray [2] = {@link perhaunit＃kilowatt_hour}\r\n</ul>','EV battery units for display.\r\n<p>Indicates which units the vehicle is using to display EV battery information to the user.\r\n<p>configArray represents the list of supported units for {@code\r\nEV_BATTERY_DISPLAY_UNITS}. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleUnit#WATT_HOUR}\r\n <li>configArray[1] = {@link VehicleUnit#AMPERE_HOURS}\r\n <li>configArray[2] = {@link VehicleUnit#KILOWATT_HOUR}\r\n</ul>','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(77,289408516,'VEHICLE_SPEED_DISPLAY_UNITS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','速度单元显示。\r\n<p>表示车辆使用的单元类型将速度显示给用户。\r\n<p> configarray表示{@code的支持单元的列表\r\nwarter_speed_display_units}。这是一个示例configarray：\r\n<ul>\r\n<li> configArray [0] = {@link wareyunit＃meter_per_sec}\r\n<li> configArray [1] = {@link wareyunit＃miles_per_hour}\r\n<li> configarray [2] = {@link perhaunit＃kilomes_per_hour}\r\n</ul>','Speed units for display.\r\n<p>Indicates type of units the vehicle is using to display speed to user.\r\n<p>configArray represents the list of supported units for {@code\r\nVEHICLE_SPEED_DISPLAY_UNITS}. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = {@link VehicleUnit#METER_PER_SEC}\r\n <li>configArray[1] = {@link VehicleUnit#MILES_PER_HOUR}\r\n <li>configArray[2] = {@link VehicleUnit#KILOMETERS_PER_HOUR}\r\n</ul>','google',1,'VehicleUnit',0,'2024-11-13 17:14:33','',0),(78,287311364,'FUEL_CONSUMPTION_UNITS_DISTANCE_OVER_VOLUME','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','燃料消耗单元用于显示。\r\n<p>表示汽车使用的单元类型用于向用户显示燃料消耗信息。\r\n<p> {@code true}指示单位的距离超过卷，例如mpg。\r\n<p> {@code false}指示单位是距离范围内的，例如l/100km。','Fuel consumption units for display.\r\n<p>Indicates type of units the car is using to display fuel consumption information to user.\r\n<p>{@code true} indicates units are distance over volume such as MPG.\r\n<p>{@code false} indicates units are volume over distance such as L/100KM.','google',1,'',0,'2024-11-13 17:14:33','',0),(79,291505923,'ENV_OUTSIDE_TEMPERATURE','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','摄氏的外部温度。','Outside temperature in celsius.','google',1,'',0,'2024-11-13 17:14:33','',0),(80,287312389,'VALET_MODE_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用了代客模式\r\n<p>此属性允许用户在车辆中启用/禁用代客模式。代客模式是\r\n一种隐私和安全设置，可防止不受信任的驾驶员访问更多私人区域\r\n在车辆中，例如杂物盒或后备箱。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Valet mode enabled\r\n<p>This property allows the user to enable/disable valet mode in their vehicle. Valet mode is\r\na privacy and security setting that prevents an untrusted driver to access more private areas\r\nin the vehicle, such as the glove box or the trunk(s).\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(81,354421254,'HEAD_UP_DISPLAY_ENABLED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用（HUD）启用\r\n<p>此属性允许用户打开/关闭HUD的座位。\r\n<p>车辆中的每个HUD都将分配到旨在使用它的座椅上。为了\r\n例如，如果车辆中有一个HUD，则驾驶员使用\r\n更长的时间需要连续查看仪器仪表，然后该属性将是\r\n定义的单个区域ID等于驾驶员座区域ID。','Head up display (HUD) enabled\r\n<p>This property allows the user to turn on/off the HUD for their seat.\r\n<p>Each HUD in the vehicle will be assigned to the seat that is intended to use it. For\r\nexample, if there is a single HUD in the vehicle that is used by the driver so that they no\r\nlonger need to continuously look at the instrument cluster, then this property will be\r\ndefined with a single area ID that is equal to the driver\'s seat area ID.','google',1,'',0,'2024-11-13 17:14:33','',0),(82,373295872,'DOOR_POS','VEHICLE_AREA_TYPE_DOOR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','门位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示门的\r\n关闭时位置。这个值将为0\r\n<p> {@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}指示门的\r\n完全打开时位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在封闭和完全开放的位置之间。','Door position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the door\'s\r\nposition when closed. This value will be 0\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the door\'s\r\nposition when fully open.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the closed and fully open positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(83,373295873,'DOOR_MOVE','VEHICLE_AREA_TYPE_DOOR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','门移。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着门正在打开，负值意味着门正在关闭。\r\n较大的整数（正或负数）表示更快的速度。一旦门到达\r\n位置限制，值重置为0。当此属性的值为0时，这意味着\r\n目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Door move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the door is opening and negative values mean the door is closing.\r\nLarger integers, either positive or negative, indicate a faster speed. Once the door reaches\r\nthe positional limit, the value resets to 0. When this property\'s value is 0, that means\r\nthere is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(84,371198722,'DOOR_LOCK','VEHICLE_AREA_TYPE_DOOR','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','门锁。\r\n<p> true表示门已锁定。','Door lock.\r\n<p>True indicates that the door is locked.','google',1,'',0,'2024-11-13 17:14:33','',0),(85,371198723,'DOOR_CHILD_LOCK_ENABLED','VEHICLE_AREA_TYPE_DOOR','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用了门子锁功能。\r\n<p>如果启用了门子锁定功能，则返回true，如果禁用了false。\r\n如果启用，门将无法从内部打开。','Door child lock feature enabled.\r\n<p>Returns true if the door child lock feature is enabled and false if it is disabled.\r\nIf enabled, the door is unable to be opened from the inside.','google',1,'',0,'2024-11-13 17:14:33','',0),(86,339741504,'MIRROR_Z_POS','VEHICLE_AREA_TYPE_MIRROR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜子z位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示镜像的\r\n当完全向下倾斜时，位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示镜像的\r\n当完全向上倾斜时，位置。\r\n<p> 0表示镜子在任何方向上都不倾斜。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在完全向下和完全向上的位置之间。','Mirror Z Position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the mirror\'s\r\nposition when tilted completely downwards.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the mirror\'s\r\nposition when tilted completely upwards.\r\n<p>0 indicates the mirror is not tilted in either direction.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the completely downwards and completely upwards positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(87,339741505,'MIRROR_Z_MOVE','VEHICLE_AREA_TYPE_MIRROR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜子z移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值表示镜子正在倾斜，负值表示镜子为\r\n倾斜。较大的整数（正或负数）表示更快的速度。一旦\r\n镜像达到位置限制，值重置为0。当此属性的值为0时，\r\n这意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Mirror Z Move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the mirror is tilting up and negative values mean the mirror is\r\ntilting down. Larger integers, either positive or negative, indicate a faster speed. Once the\r\nmirror reaches the positional limit, the value resets to 0. When this property\'s value is 0,\r\nthat means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(88,339741506,'MIRROR_Y_POS','VEHICLE_AREA_TYPE_MIRROR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜像位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示镜像的\r\n当完全向左倾斜时，位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示镜像的\r\n当完全向右倾斜时，位置。\r\n<p> 0表示镜子在任何方向上都不倾斜。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在极端和极端的位置之间。','Mirror Y Position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the mirror\'s\r\nposition when tilted completely to the left.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the mirror\'s\r\nposition when tilted completely to the right.\r\n<p>0 indicates the mirror is not tilted in either direction.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the extreme left and extreme right positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(89,339741507,'MIRROR_Y_MOVE','VEHICLE_AREA_TYPE_MIRROR','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜像y移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着镜子向右倾斜，负值表示\r\n支持向左倾斜。较大的整数（正或负数）表示\r\n更快的速度。镜子达到位置极限后，值将重置为0。\r\n属性的值为0，这意味着目前没有移动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Mirror Y Move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the mirror is tilting to the right and negative values mean the\r\nsupport is tilting to the left. Larger integers, either positive or negative, indicate a\r\nfaster speed. Once the mirror reaches the positional limit, the value resets to 0. When this\r\nproperty\'s value is 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(90,287312708,'MIRROR_LOCK','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜子锁。\r\n<p> true表示所有镜像位置均已锁定并且不变。','Mirror Lock.\r\n<p>True indicates all mirror positions are locked and not changeable.','google',1,'',0,'2024-11-13 17:14:33','',0),(91,287312709,'MIRROR_FOLD','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','镜子折。','Mirror Fold.','google',1,'',0,'2024-11-13 17:14:33','',0),(92,337644358,'MIRROR_AUTO_FOLD_ENABLED','VEHICLE_AREA_TYPE_MIRROR','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表镜像自动折叠功能的属性。\r\n<p>当用于自动折叠车辆镜子的功能时，此属性是正确的\r\n（例如，当镜子出口并锁定时，镜子会自动折叠\r\n车辆）已启用。','Represents property for the Mirror Auto Fold feature.\r\n<p>This property is true when the feature for automatically folding the vehicle\'s mirrors\r\n(for example, when the mirrors fold inward automatically when one exits and locks the\r\nvehicle) is enabled.','google',1,'',0,'2024-11-13 17:14:33','',0),(93,337644359,'MIRROR_AUTO_TILT_ENABLED','VEHICLE_AREA_TYPE_MIRROR','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表镜像自动倾斜功能的属性。\r\n<p>当用于自动倾斜车辆的镜子的功能时，此属性是正确的\r\n（例如，当镜子在逆转车辆时自动向下倾斜时）\r\n启用。','Represents property for the Mirror Auto Tilt feature.\r\n<p>This property is true when the feature for automatically tilting the vehicle\'s mirrors\r\n(for example, when the mirrors tilt downward automatically when one reverses the vehicle) is\r\nenabled.','google',1,'',0,'2024-11-13 17:14:33','',0),(94,356518896,'GLOVE_BOX_DOOR_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表杂物盒门的当前位置的属性。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n态\r\n关闭时位置。此值将为0。\r\n态\r\n完全打开时位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在封闭和完全开放的位置之间。\r\n<p>受支持的区域ID与供应使用的座椅相匹配\r\n（例如）如果右前仪表板嵌入了杂物盒，则区域ID应该\r\nbe {@link vericleareaseat＃seat_row_1_right}）。','Property that represents the current position of the glove box door.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the glove box\'s\r\nposition when closed. This value will be 0.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the glove box\'s\r\nposition when fully open.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the closed and fully open positions.\r\n<p>The supported area IDs match the seat(s) by which the glove box is intended to be used\r\n(e.g.) if the front right dashboard has a glove box embedded in it, then the area ID should\r\nbe {@link VehicleAreaSeat#SEAT_ROW_1_RIGHT}).','google',1,'',0,'2024-11-13 17:14:33','',0),(95,354421745,'GLOVE_BOX_LOCKED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','锁定或解锁杂物盒。\r\n<p>如果{@code true}，则锁定了杂物框。如果{@code false}，则解锁杂物框。\r\n<p>受支持的区域ID与供应使用的座椅相匹配\r\n（例如，如果右前仪表板嵌入了一个杂物盒，则区域ID为\r\n{@link android.car.vehicleareaseat＃seat_row_1_right}）。','Lock or unlock the glove box.\r\n<p>If {@code true}, the glove box is locked. If {@code false}, the glove box is unlocked.\r\n<p>The supported area IDs match the seat(s) by which the glove box is intended to be used\r\n(e.g. if the front right dashboard has a glove box embedded in it, then the area ID will be\r\n{@link android.car.VehicleAreaSeat#SEAT_ROW_1_RIGHT}).','google',1,'',0,'2024-11-13 17:14:33','',0),(96,356518784,'SEAT_MEMORY_SELECT','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅记忆选择。\r\n<p>此参数选择用于选择座位位置的内存预设。{@link\r\nandroid.car.hardware.property.areaidconfig＃getminvalue（）}始终为0，{@link\r\nandroid.car.hardware.property.areaidconfig＃getmaxvalue（）}确定座位的数量\r\n可用的位置（即NumseatPreesets -1）。','Seat memory select.\r\n<p>This parameter selects the memory preset to use to select the seat position. The {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} is always 0, and the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMaxValue()} determines the number of seat\r\npositions available (i.e. numSeatPresets - 1).','google',1,'',0,'2024-11-13 17:14:33','',0),(97,356518785,'SEAT_MEMORY_SET','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅内存集。\r\n<p>此设置允许用户将当前座位位置设置保存到所选的\r\n预设插槽。每个\r\n座位位置必须匹配{@link android.car.hardware.property.areaidConfig＃getMaxvalue（）}\r\n对于{@link #seat_memory_select}。','Seat memory set.\r\n<p>This setting allows the user to save the current seat position settings into the selected\r\npreset slot. The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} for each\r\nseat position must match the {@link android.car.hardware.property.AreaIdConfig#getMaxValue()}\r\nfor {@link #SEAT_MEMORY_SELECT}.','google',1,'',0,'2024-11-13 17:14:33','',0),(98,354421634,'SEAT_BELT_BUCKLED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','安全带搭扣。\r\n<p> true表明皮带是弯曲的。','Seatbelt buckled.\r\n<p>True indicates belt is buckled.','google',1,'',0,'2024-11-13 17:14:33','',0),(99,356518787,'SEAT_BELT_HEIGHT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','安全带高度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}表示安全带\r\n肩锚的最低位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}表示安全带\r\n肩锚的最高位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最低和最高位置之间。','Seatbelt height position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat belt\r\nshoulder anchor\'s lowest position.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat belt\r\nshoulder anchor\'s highest position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the lowest and highest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(100,356518788,'SEAT_BELT_HEIGHT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','安全带高度移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着安全带的肩膀锚在向上移动，负值表示\r\n安全带的肩膀锚在向下移动。较大的整数，无论​​是正面还是负面，\r\n表示更快的速度。一旦安全带的肩膀锚达到位置极限，\r\n值重置为0。当此属性的值为0时，这意味着没有移动\r\n目前发生。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seatbelt height move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat belt\'s shoulder anchor is moving up and negative values mean\r\nthe seat belt\'s shoulder anchor is moving down. Larger integers, either positive or negative,\r\nindicate a faster speed. Once the seat belt\'s shoulder anchor reaches the positional limit,\r\nthe value resets to 0. When this property\'s value is 0, that means there is no movement\r\ncurrently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(101,356518789,'SEAT_FORE_AFT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座位前/船尾位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}表示座椅的\r\n最向后的线性位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}表示座椅的\r\n前向线性位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Seat fore/aft position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\'s\r\nrearward-most linear position.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\'s\r\nforward-most linear position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(102,356518790,'SEAT_FORE_AFT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座位前/后移动。\r\n<p>此属性将整个座椅向前/向后移动，以其面向的方向向后移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座椅正在向前移动，负值意味着座椅是\r\n向后移动。较大的整数（正或负数）表示更快的速度。一次\r\n座位达到位置限制，值重置为0。当此属性的值为\r\n0，这意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat fore/aft move.\r\n<p>This property moves the entire seat forward/backward in the direction it\'s facing.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat is moving forward and negative values mean the seat is\r\nmoving backward. Larger integers, either positive or negative, indicate a faster speed. Once\r\nthe seat reaches the positional limit, the value resets to 0. When this property\'s value is\r\n0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(103,356518791,'SEAT_BACKREST_ANGLE_1_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅靠背角1位。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示座椅\r\nBackrest的完整倾斜位置W.R.T座椅底部的执行器（请参阅{@link\r\n＃seat_backrest_angle_1_move}有关其他详细信息）。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\nBackrest最直立/向前的位置W.R.T座椅底部的执行器（请参阅\r\n{@link＃seat_backrest_angle_1_move}有关其他详细信息）。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Seat backrest angle 1 position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nbackrest\'s full recline position w.r.t the actuator at the bottom of the seat (see {@link\r\n#SEAT_BACKREST_ANGLE_1_MOVE} for additional details).\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nbackrest\'s most upright/forward position w.r.t the actuator at the bottom of the seat (see\r\n{@link #SEAT_BACKREST_ANGLE_1_MOVE} for additional details).\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(104,356518792,'SEAT_BACKREST_ANGLE_1_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅靠背角1移动。\r\n<p>此属性沿着执行器定义的旋转轴移动座椅\r\n最接近座椅的底部。这是将座椅直立移动/向前移动座椅的执行器\r\n或在大多数传统车辆中看到的斜视。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座椅向前垂直，负值表示座椅是\r\n向后倾斜。较大的整数（正或负数）表示更快的速度。\r\n座位达到位置极限后，值将重置为0。当此属性的值时\r\n是0，这意味着目前没有发生运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat backrest angle 1 move.\r\n<p>This property moves the seat backrest along the axis of rotation defined by the actuator\r\nclosest to the bottom of the seat. This is the actuator that moves the seat upright/forward\r\nor into recline as seen in most conventional vehicles.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat is angling forward and negative values mean the seat is\r\nreclining backward. Larger integers, either positive or negative, indicate a faster speed.\r\nOnce the seat reaches the positional limit, the value resets to 0. When this property\'s value\r\nis 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(105,356518793,'SEAT_BACKREST_ANGLE_2_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座位靠背角2位。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示座椅\r\nBackrest的完整倾斜位置W.R.T靠背的下一个执行器\r\n座椅底部（有关更多详细信息，请参见{@link＃seat_backrest_angle_2_move}）。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n靠背的最直立/前进位置W.R.T靠背中的下一个执行器\r\n在座椅的底部（有关更多详细信息，请参见{@link＃seat_backrest_angle_2_move}）。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Seat backrest angle 2 position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nbackrest\'s full recline position w.r.t the next actuator in the backrest from the one at the\r\nbottom of the seat (see {@link #SEAT_BACKREST_ANGLE_2_MOVE} for more details).\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nbackrest\'s most upright/forward position w.r.t the next actuator in the backrest from the one\r\nat the bottom of the seat (see {@link #SEAT_BACKREST_ANGLE_2_MOVE} for more details).\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(106,356518794,'SEAT_BACKREST_ANGLE_2_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座位靠背角2移动。\r\n<p>如果在座位中存在额外的执行器，将实施此属性\r\n靠近靠背的靠背，靠背的底层{@link覆盖了\r\n＃seat_backrest_angle_1_move}。该特性将沿着旋转轴移动靠背\r\n由这个额外的执行器定义。可以假设该执行器更接近\r\n头枕比{@link＃seat_backrest_angle_1_move}定义的那个。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座椅向前垂直，负值表示座椅是\r\n向后倾斜。较大的整数（正或负数）表示更快的速度。\r\n座位达到位置极限后，值将重置为0。当此属性的值时\r\n是0，这意味着目前没有发生运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat backrest angle 2 move.\r\n<p>This property will be implemented if there exists an additional actuator in the seat\r\nbackrest besides the one at the very bottom of the backrest, which is covered by {@link\r\n#SEAT_BACKREST_ANGLE_1_MOVE}. This property will move the backrest along the axis of rotation\r\ndefined by this additional actuator. It can be assumed that this actuator is closer to the\r\nheadrest than the one defined by {@link #SEAT_BACKREST_ANGLE_1_MOVE}.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat is angling forward and negative values mean the seat is\r\nreclining backward. Larger integers, either positive or negative, indicate a faster speed.\r\nOnce the seat reaches the positional limit, the value resets to 0. When this property\'s value\r\nis 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(107,356518795,'SEAT_HEIGHT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅高度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}表示座椅的\r\n最低位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}表示座椅的\r\n最高位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最低和最高位置之间。','Seat height position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\'s\r\nlowest position.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\'s\r\nhighest position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the lowest and highest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(108,356518796,'SEAT_HEIGHT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅高度移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座椅在移动，负值表示座椅在移动\r\n向下。较大的整数（正或负数）表示更快的速度。座位后\r\n达到位置限制，值重置为0。当此属性的值为0时，\r\n意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat height move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat is moving up and negative values mean the seat is moving\r\ndown. Larger integers, either positive or negative, indicate a faster speed. Once the seat\r\nreaches the positional limit, the value resets to 0. When this property\'s value is 0, that\r\nmeans there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(109,356518797,'SEAT_DEPTH_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座位深度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}表示座椅的\r\n最浅的位置。这对应于前边缘之间的最小距离\r\n座位和座椅靠背。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}表示座椅的\r\n最深的位置。这对应于座椅前边缘之间的最大距离\r\n和座位靠背。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最浅和最深的位置之间。','Seat depth position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\'s\r\nshallowest position. This corresponds to the smallest distance between the front edge of the\r\nseat and the seat backrest.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\'s\r\ndeepest position. This corresponds to the largest distance between the front edge of the seat\r\nand the seat backrest.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the shallowest and deepest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(110,356518798,'SEAT_DEPTH_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅深度移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座椅的前边缘与座椅背面之间的距离\r\n正在增加，从而使座椅更深。负值表示\r\n座椅的前边缘和座椅的后部正在减小，从而使座椅变得较浅。\r\n较大的整数（正或负数）表示更快的速度。一旦座椅深度\r\n达到其极限，值重置为0。当此属性的值为0时，这意味着那里\r\n目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat depth move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the distance between the seat\'s front edge and the back of the seat\r\nis increasing, thus making the seat deeper. Negative values mean the distance between the\r\nseat\'s front edge and the back of the seat is decreasing, thus making the seat shallower.\r\nLarger integers, either positive or negative, indicate a faster speed. Once the seat depth\r\nreaches its limit, the value resets to 0. When this property\'s value is 0, that means there\r\nis no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(111,356518799,'SEAT_TILT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅倾斜位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示座椅\r\n底部的最低角位置。这对应于座椅的前边缘\r\n相对于座椅后端的可能位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n底部的最高角度位置。这对应于座椅的前边缘\r\n相对于座椅后端的可能位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最低和最高位置之间。','Seat tilt position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nbottom\'s lowest angular position. This corresponds to the seat\'s front edge at its lowest\r\npossible position relative to the rear end of the seat.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nbottom\'s highest angular position. This corresponds to the seat\'s front edge at its highest\r\npossible position relative to the rear end of the seat.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the lowest and highest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(112,356518800,'SEAT_TILT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅倾斜移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座垫向上倾斜，以使座垫的前部\r\n边缘高于座垫的后端。负值表示座垫\r\n向下倾斜，以使座垫的前边缘低于后端\r\n座垫。较大的整数（正或负数）表示更快的速度。一旦\r\n座垫达到位置极限，值重置为0。\r\n是0，这意味着目前没有发生运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Seat tilt move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the seat cushion is tilting upward such that the seat cushion\'s front\r\nedge is higher than the rear end of the seat cushion. Negative values mean the seat cushion\r\nis tilting downward such that the seat cushion\'s front edge is lower than the rear end of the\r\nseat cushion. Larger integers, either positive or negative, indicate a faster speed. Once the\r\nseat cushion reaches the positional limit, the value resets to 0. When this property\'s value\r\nis 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(113,356518801,'SEAT_LUMBAR_FORE_AFT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','木材前/后的位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示座椅腰\r\n支持的大多数位置（即支持位置最少）。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMaxvalue（）}表示座椅腰\r\n支持是大多数位置（即最支持的位置）。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Lumber fore/aft position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat lumbar\r\nsupport\'s rearward most position (i.e. least supportive position).\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat lumbar\r\nsupport\'s forward most position (i.e. most supportive position).\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(114,356518802,'SEAT_LUMBAR_FORE_AFT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','腰部前/后移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着腰部支撑朝向座椅的前部前进\r\n负值意味着腰部支撑正在向后移动\r\n座位。较大的整数（正或负数）表示更快的速度。一旦腰\r\n支持达到位置限制，值重置为0。当此属性的值为0时，\r\n这意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Lumbar fore/aft move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the lumbar support is moving forward towards the front of the seat\r\nand negative values mean the lumbar support is moving backward away from the front of the\r\nseat. Larger integers, either positive or negative, indicate a faster speed. Once the lumbar\r\nsupport reaches the positional limit, the value resets to 0. When this property\'s value is 0,\r\nthat means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(115,356518803,'SEAT_LUMBAR_SIDE_SUPPORT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','腰部侧支撑位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示座椅腰\r\n侧支持的最薄位置（即最大的支持）。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMaxvalue（）}表示座椅腰\r\n侧支持的最广泛位置（即支持最少）。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最薄和最宽的位置之间。','Lumbar side support position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat lumbar\r\nside support\'s thinnest position (i.e most support).\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat lumbar\r\nside support\'s widest position (i.e least support).\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the thinnest and widest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(116,356518804,'SEAT_LUMBAR_SIDE_SUPPORT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','腰部支撑移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着腰部侧支撑变得更宽（即支持更少）和\r\n负值意味着腰部侧支撑越来越薄（即更多支持）。更大\r\n整数（正或负数）表示更快的速度。一旦腰部支撑\r\n达到位置限制，值重置为0。当此属性的值为0时，\r\n意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Lumbar side support move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the lumbar side support is getting wider (i.e. less support) and\r\nnegative values mean the lumbar side support is getting thinner (i.e. more support). Larger\r\nintegers, either positive or negative, indicate a faster speed. Once the lumbar side support\r\nreaches the positional limit, the value resets to 0. When this property\'s value is 0, that\r\nmeans there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(117,356518820,'SEAT_HEADREST_HEIGHT_POS_V2','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕高度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}指示座椅\r\n头枕的最短位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n头枕的最高位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最短和最高的位置之间。\r\n<p> {@link android.car.hardware.carpropertyconfig＃getareAids（）}指定哪些座位是\r\n支持。','Headrest height position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nheadrest\'s shortest position.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nheadrest\'s tallest position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the shortest and tallest positions.\r\n<p>{@link android.car.hardware.CarPropertyConfig#getAreaIds()} specifies which seats are\r\nsupported.','google',1,'',0,'2024-11-13 17:14:33','',0),(118,356518806,'SEAT_HEADREST_HEIGHT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕高度移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着头枕在向上移动，负值表示头枕是\r\n向下移动。较大的整数（正或负数）表示更快的速度。一旦\r\n头枕达到位置限制，值重置为0。当此属性的值为\r\n0，这意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Headrest height move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the headrest is moving up and negative values mean the headrest is\r\nmoving down. Larger integers, either positive or negative, indicate a faster speed. Once the\r\nheadrest reaches the positional limit, the value resets to 0. When this property\'s value is\r\n0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(119,356518807,'SEAT_HEADREST_ANGLE_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕角度。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}指示座椅\r\nHeadrest的完整倾斜位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n头枕是最直立/前进的位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Headrest angle position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nheadrest\'s full recline position.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nheadrest\'s most upright/forward position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(120,356518808,'SEAT_HEADREST_ANGLE_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕角度移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着头枕在直立/向前移动，负值表示\r\n头枕在斜倚。较大的整数（正或负数）表示更快的速度。\r\n一旦头枕达到位置限制，值将重置为0。\r\n值为0，这意味着目前没有移动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Headrest angle move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the headrest is moving upright/forward and negative values mean the\r\nheadrest is reclining. Larger integers, either positive or negative, indicate a faster speed.\r\nOnce the headrest reaches the positional limit, the value resets to 0. When this property\'s\r\nvalue is 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(121,356518809,'SEAT_HEADREST_FORE_AFT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕前/船尾位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}指示座椅\r\n头枕的最向后线性位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n头枕的前向线性位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在大多数位置之间的前进和向后之间。','Headrest fore/aft position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nheadrest\'s rearward-most linear position.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nheadrest\'s forward-most linear position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the forward most and rearward most positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(122,356518810,'SEAT_HEADREST_FORE_AFT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','头枕前/后移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着头枕向前向座位的前部前进，\r\n负值意味着头枕从座椅前方移动。更大\r\n整数（正或负数）表示更快的速度。一旦头枕到达\r\n位置限制，值重置为0。当此属性的值为0时，这意味着有\r\n目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Headrest fore/aft move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the headrest is moving forward towards the front of the seat and\r\nnegative values mean the headrest is moving backward away from the front of the seat. Larger\r\nintegers, either positive or negative, indicate a faster speed. Once the headrest reaches the\r\npositional limit, the value resets to 0. When this property\'s value is 0, that means there is\r\nno movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(123,356518811,'SEAT_FOOTWELL_LIGHTS_STATE','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表脚步灯状态的财产。\r\n<p> {@code seat_footwell_lights_state}在任何时候反映了当前的灯光状态\r\n及时。这与{@link #seat_footwell_lights_switch}的功能不同\r\n表示控制灯的开关的位置。因此，{@code\r\nseat_footwell_lights_state}可能与{@link #seat_footwell_lights_switch}的值不匹配\r\n（例如{@link #seat_footwell_lights_switch} = {@code vericlelightswitch＃state_automatic}和\r\n{@Code SEAT_FOOTWELL_LIGHTS_STATE} = {@code vericlelightState＃state_on}）。\r\n<p>仅当{@code seat_footwell_lights_state}的值可能才能实现此属性\r\n与{@link #cabin_lights_state}不同。\r\n<p>对于每个受支持的区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getsupportedenumvalues（）}从{@link获得\r\nandroid.car.hardware.carpropertyconfig＃getAreAidConfig（int）}指定从\r\n{@code vericlelightstate}得到了支持。','Represents property for state of the footwell lights.\r\n<p>{@code SEAT_FOOTWELL_LIGHTS_STATE} reflects the current state of the lights at any point\r\nin time. This is different from the function of {@link #SEAT_FOOTWELL_LIGHTS_SWITCH} which\r\nrepresents the position of the switch controlling the lights. Therefore, {@code\r\nSEAT_FOOTWELL_LIGHTS_STATE} may not match the value of {@link #SEAT_FOOTWELL_LIGHTS_SWITCH}\r\n(e.g. {@link #SEAT_FOOTWELL_LIGHTS_SWITCH}={@code VehicleLightSwitch#STATE_AUTOMATIC} and\r\n{@code SEAT_FOOTWELL_LIGHTS_STATE}={@code VehicleLightState#STATE_ON}).\r\n<p>This property will only be implemented if {@code SEAT_FOOTWELL_LIGHTS_STATE}\'s value may\r\nbe different from that of {@link #CABIN_LIGHTS_STATE}.\r\n<p>For each supported area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} obtained from {@link\r\nandroid.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum values from\r\n{@code VehicleLightState} are supported.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(124,356518812,'SEAT_FOOTWELL_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表脚步灯开关的属性。\r\n<p> {@code seat_footwell_lights_switch}表示控制开关的位置\r\n灯。这与{@link #seat_footwell_lights_state}的功能不同\r\n在任何时间点都反映灯的当前状态。因此，{@code\r\nseat_footwell_lights_switch}可能不匹配{@link #seat_footwell_lights_state}的值\r\n（例如{@code Seat_footwell_lights_switch} = {@code vericlelightswitch＃state_automatic}和\r\n{@link #seat_footwell_lights_state} = {@code vericlelightState＃state_on}）。\r\n<p>仅当{@code seat_footwell_lights_switch}的值可能才能实现此属性\r\n与{@link #cabin_lights_switch}不同。\r\n<p>对于每个受支持的区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getsupportedenumvalues（）}从{@link获得\r\nandroid.car.hardware.carpropertyconfig＃getAreAidConfig（int）}指定从\r\n{@code vericlelightswitch}得到了支持。','Represents property for switch of the footwell lights.\r\n<p>{@code SEAT_FOOTWELL_LIGHTS_SWITCH} represents the position of the switch controlling the\r\nlights. This is different from the function of {@link #SEAT_FOOTWELL_LIGHTS_STATE} which\r\nreflects the current state of the lights at any point in time. Therefore, {@code\r\nSEAT_FOOTWELL_LIGHTS_SWITCH} may not match the value of {@link #SEAT_FOOTWELL_LIGHTS_STATE}\r\n(e.g. {@code SEAT_FOOTWELL_LIGHTS_SWITCH}={@code VehicleLightSwitch#STATE_AUTOMATIC} and\r\n{@link #SEAT_FOOTWELL_LIGHTS_STATE}={@code VehicleLightState#STATE_ON}).\r\n<p>This property will only be implemented if {@code SEAT_FOOTWELL_LIGHTS_SWITCH}\'s value may\r\nbe different from that of {@link #CABIN_LIGHTS_SWITCH}.\r\n<p>For each supported area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} obtained from {@link\r\nandroid.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum values from\r\n{@code VehicleLightSwitch} are supported.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(125,354421661,'SEAT_EASY_ACCESS_ENABLED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表座位易于访问功能的属性。\r\n<p>如果是真的，座椅将自动调整以使乘员更容易进入\r\n并退出车辆。每个区域ID映射到用户试图输入/退出的座椅\r\n借助轻松访问功能。','Represents property for Seat easy access feature.\r\n<p>If true, the seat will automatically adjust to make it easier for the occupant to enter\r\nand exit the vehicle. Each area ID maps to the seat that the user is trying to enter/exit\r\nwith the help of the easy access feature.','google',1,'',0,'2024-11-13 17:14:33','',0),(126,354421662,'SEAT_AIRBAG_ENABLED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表功能以启用/禁用座椅的部署安全气囊的能力\r\n（例如，发生崩溃）。\r\n<p>如果是真的，则意味着座椅的安全气囊已启用，如果触发（例如，碰撞），它们\r\n将部署。如果是错误的，则意味着座椅的安全气囊被禁用，它们不会部署\r\n在任何情况下。此属性未指示安全气囊是否已部署。','Represents feature to enable/disable a seat\'s ability to deploy airbag(s) when triggered\r\n(e.g. by a crash).\r\n<p>If true, it means the seat\'s airbags are enabled, and if triggered (e.g. by a crash), they\r\nwill deploy. If false, it means the seat\'s airbags are disabled, and they will not deploy\r\nunder any circumstance. This property does not indicate if the airbags are deployed or not.','google',1,'',0,'2024-11-13 17:14:33','',0),(127,356518821,'SEAT_AIRBAGS_DEPLOYED','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅安全气囊的部署状态。\r\n<p>位标志属性以中继有关在车辆中部署哪些安全气囊的信息\r\n在每个座位上，与目前仍是哪些座位。当seat_airbag_enabled设置为\r\n在特定的区域ID上，该属性在该apeardID中将无法使用。\r\n<p>枚举适用于每个座位，而不是全球车辆。例如，\r\n{@link android.car.hardware.property.vehicleairbaglocation＃Curtain}\r\n表示驾驶员侧窗帘安全气囊是否已部署。多个位标志可以\r\n被设置为表明座椅已部署了多个不同的安全气囊。\r\n<p>对于每个座位区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n支持{@link android.car.hardware.property.vehicleairbaglocation}。','State of deployment for seat airbags.\r\n<p>Bit flag property to relay information on which airbags have been deployed in the vehicle\r\nat each seat, vs which ones are currently still armed. When SEAT_AIRBAG_ENABLED is set to\r\nfalse at a particular areaId, this property will be UNAVAILABLE at that areaId.\r\n<p>Enums apply to each seat, not the global vehicle. For example,\r\n{@link android.car.hardware.property.VehicleAirbagLocation#CURTAIN} at the driver seat areaId\r\nrepresents whether the driver side curtain airbag has been deployed. Multiple bit flags can\r\nbe set to indicate that multiple different airbags have been deployed for the seat.\r\n<p>For each seat area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.VehicleAirbagLocation} are supported.','google',1,'android.car.hardware.property.VehicleAirbagLocation',0,'2024-11-13 17:14:33','',0),(128,356518815,'SEAT_CUSHION_SIDE_SUPPORT_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表座位的hipside（底部缓冲侧）支撑位置的财产。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}指示座椅\r\nHipside支持的最薄位置（即最大的支持）。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\nHipside支持的最广泛位置（即支持最少）。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最薄和最宽的位置之间。','Represents property for seat鈥檚 hipside (bottom cushion鈥檚 side) support position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nhipside support\'s thinnest position (i.e. most support).\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nhipside support\'s widest position (i.e. least support).\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the thinnest and widest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(129,356518816,'SEAT_CUSHION_SIDE_SUPPORT_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表座椅垫侧支撑的运动方向和速度的属性。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着座垫侧支撑越来越大（即支持更少）\r\n负值意味着座垫侧支撑越来越薄（即更多\r\n支持）。较大的整数（正或负数）表示更快的速度。一旦\r\n座垫侧支撑达到位置极限，值重置为0。\r\n属性的值为0，这意味着目前没有移动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Represents property for movement direction and speed of seat cushion side support.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values means the seat cushion side support is growing wider (i.e. less support)\r\nand negative values means the seat cushion side support is growing thinner (i.e. more\r\nsupport). Larger integers, either positive or negative, indicate a faster speed. Once the\r\nseat cushion side support reaches the positional limit, the value resets to 0. When this\r\nproperty\'s value is 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(130,356518817,'SEAT_LUMBAR_VERTICAL_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表座椅的腰部支撑垂直位置的特性。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getMinvalue（）}指示座椅\r\n腰部支持的最低位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示座椅\r\n腰部支持的最高位置。\r\n<p>支持最小值和最大值之间的所有整数，并指示过渡状态\r\n在最低和最高位置之间。','Represents property for seat鈥檚 lumbar support vertical position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the seat\r\nlumbar support\'s lowest position.\r\n<p>The {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\r\nlumbar support\'s highest position.\r\n<p>All integers between the min and max values are supported and indicate a transition state\r\nbetween the lowest and highest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(131,356518818,'SEAT_LUMBAR_VERTICAL_MOVE','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','代表垂直移动方向和座椅腰部支撑速度的属性。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着腰部支撑在移动，负值表示腰\r\n支持正在向下移动。较大的整数（正或负数）表示更快\r\n速度。一旦腰部支撑达到位置限制，该值将重置为0。\r\n属性的值为0，这意味着目前没有移动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Represents property for vertical movement direction and speed of seat lumbar support.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the lumbar support is moving up and negative values mean the lumbar\r\nsupport is moving down. Larger integers, either positive or negative, indicate a faster\r\nspeed. Once the lumbar support reaches the positional limit, the value resets to 0. When this\r\nproperty\'s value is 0, that means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(132,356518819,'SEAT_WALK_IN_POS','VEHICLE_AREA_TYPE_SEAT','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','表示指示座椅当前步入位置的属性。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示正常座椅\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}表示座椅的\r\n以完整的步入模式定位。\r\n<p>支持最小值和最大值之间的所有整数，并表示过渡\r\n在正常位置和步入式位置之间进行状态。区域ID与实际座位相匹配\r\n步入式功能激活时移动。','Represents property that indicates the current walk-in position of the seat.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the normal seat\r\nposition.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the seat\'s\r\nposition in full walk-in mode.\r\n<p>All integers in between the min and max values are supported and indicate a transition\r\nstate between the normal and walk-in positions. The area IDs match the seats that actually\r\nmove when the walk-in feature activates.','google',1,'',0,'2024-11-13 17:14:33','',0),(133,354421670,'SEAT_BELT_PRETENSIONER_DEPLOYED','VEHICLE_AREA_TYPE_SEAT','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','安全带预感器部署了。\r\n<p>财产传递有关安全带预紧者是否已部署的信息\r\n由于碰撞而引起的特定座位。这与常规安全带紧绷不同\r\n不断增加紧张局势的系统，使它们紧密地适合\r\n坐在座位上的人，也不是安全带的安全带牵开器系统\r\n突然制动期间或用户拉动安全带时，就位。\r\n<p>如果此属性取决于其他属性的状态，以及这些属性\r\n目前处于不支持此属性的州，阅读此属性将\r\n投掷{@link android.car.hardware.property.propertynotavailableException}。','Seat belt pretensioner deployed.\r\n<p>Property to relay information on whether the seat belt pretensioner has been deployed for\r\na particular seat due to a collision. This is different from the regular seat belt tightening\r\nsystem that continuously adds tension to the seat belts so that they fit snugly around the\r\nperson sitting in the seat, nor is it the seat belt retractor system that locks the seat belt\r\nin place during sudden brakes or when the user jerks the seat belt.\r\n<p>If this property is dependant on the state of other properties, and if those properties\r\nare currently in the state that doesn\'t support this property, reading this property will\r\nthrow {@link android.car.hardware.property.PropertyNotAvailableException}.','google',1,'',0,'2024-11-13 17:14:33','',0),(134,356518832,'SEAT_OCCUPANCY','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','座椅占用。','Seat Occupancy.','google',1,'VehicleSeatOccupancyState',0,'2024-11-13 17:14:33','',0),(135,322964416,'WINDOW_POS','VEHICLE_AREA_TYPE_WINDOW','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','窗口位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示窗口的\r\n当关闭/完全开放平面时位置。如果窗口无法从飞机上打开，则\r\n{@link android.car.hardware.property.areaidconfig＃getminvalue（）}是\r\n窗口完全关闭并且必须为0。如果窗口可以从飞机上打开，{@link\r\nandroid.car.hardware.property.areaidconfig＃getminvalue（）}指示窗口完全打开\r\n在其位置以外的位置，将是一个负值。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}指示窗口的\r\n完全打开时位置。\r\n<p>支持最小值和最大值之间的所有整数，并表示过渡\r\n在封闭式和完全开放的位置之间进行状态。','Window Position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the window\'s\r\nposition when closed/fully open out of plane. If the window cannot open out of plane, then\r\n{@link android.car.hardware.property.AreaIdConfig#getMinValue()} is the position of the\r\nwindow when fully closed and must be 0. If the window can open out of plane, {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} indicates the window is fully open\r\nin its position out of plane and will be a negative value.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the window\'s\r\nposition when fully open.\r\n<p>All integers in between the min and max values are supported and indicate a transition\r\nstate between the closed and fully open positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(136,322964417,'WINDOW_MOVE','VEHICLE_AREA_TYPE_WINDOW','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','窗口移动。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对运动范围内\r\n速度。\r\n<p>正值意味着窗口要么从其偏离平面位置关闭（如果这样\r\n窗口支持一个位置），或在平面上打开。负值意味着\r\n窗口在平面上关闭，或在其脱离平面位置上打开（如果位置为\r\n支持）。较大的整数（正或负数）表示更快的速度。一旦\r\n窗口达到位置限制，值重置为0。当此属性的值为0时，\r\n这意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Window Move.\r\n<p>This property is not in any particular unit but in a specified range of relative movement\r\nspeeds.\r\n<p>Positive values mean the window is either closing from its out of plane position (if such\r\na position is supported by the window), or is opening in plane. Negative values mean the\r\nwindow is closing in plane, or opening in its out of plane position (if the position is\r\nsupported). Larger integers, either positive or negative, indicate a faster speed. Once the\r\nwindow reaches the positional limit, the value resets to 0. When this property\'s value is 0,\r\nthat means there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(137,320867268,'WINDOW_LOCK','VEHICLE_AREA_TYPE_WINDOW','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','窗户锁。\r\n<p> true表示窗口是子锁的。','Window Child Lock.\r\n<p>True indicates that the window is child-locked.','google',1,'',0,'2024-11-13 17:14:33','',0),(138,322964421,'WINDSHIELD_WIPERS_PERIOD','VEHICLE_AREA_TYPE_WINDOW','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','挡风玻璃雨刷时期（毫秒）。\r\n<p>在{@link中返回挡风玻璃雨刮器的整个瞬时时间段\r\nandroid.car.vehicleunit＃milli_secs}。一个完整的周期定义为刮水器从和\r\n返回其休息位置。{@link\r\nandroid.car.hardware.property.areaidConfig＃getMaxvalue（）}指定最长的雨刮器期。\r\n{@link android.car.hardware.property.areaidConfig＃getminvalue（）}}始终是0。\r\n选择了间歇性的雨刮器设置，此属性值将在此期间设置为0\r\n间歇性擦拭的“暂停”阶段。','Windshield wipers period (milliseconds).\r\n<p>Returns the instantaneous time period for 1 full cycle of the windshield wipers in {@link\r\nandroid.car.VehicleUnit#MILLI_SECS}. A full cycle is defined as a wiper moving from and\r\nreturning to its rest position. The {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMaxValue()} specifies the longest wiper period.\r\nThe {@link android.car.hardware.property.AreaIdConfig#getMinValue()} is always 0. When an\r\nintermittent wiper setting is selected, this property value will be set to 0 during the\r\n\"\"pause\"\" phase of the intermittent wiping.','google',1,'',0,'2024-11-13 17:14:33','',0),(139,322964422,'WINDSHIELD_WIPERS_STATE','VEHICLE_AREA_TYPE_WINDOW','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','挡风玻璃状态。\r\n<p>返回挡风玻璃刮水器的当前状态。{@code的值\r\nwindshield_wipers_state}可能与{@link #windshield_wipers_switch}的值不匹配。（例如。\r\n{@code #windshield_wipers_state} = {@link\r\nandroid.car.hardware.property.windshieldwipersstate＃on}和{@link\r\n#windshield_wipers_switch} = {@link\r\nandroid.car.hardware.property.windshieldwipersswitch＃auto}）。\r\n<p>如果{@code #windshield_wipers_state} = {@link\r\nandroid.car.hardware.property.windshieldwipersstate＃on}和{@link #windshield_wipers_period}\r\n已实现，然后{@link #windshield_wipers_period}将反映1的时间段\r\n刮水器的完整周期。\r\n<p>对于每个受支持的区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n支持{@link android.car.hardware.property.windshieldwipersstate}。','Windshield wipers state.\r\n<p>Returns the current state of the windshield wipers. The value of {@code\r\nWINDSHIELD_WIPERS_STATE} may not match the value of {@link #WINDSHIELD_WIPERS_SWITCH}. (e.g.\r\n{@code #WINDSHIELD_WIPERS_STATE} = {@link\r\nandroid.car.hardware.property.WindshieldWipersState#ON} and {@link\r\n#WINDSHIELD_WIPERS_SWITCH} = {@link\r\nandroid.car.hardware.property.WindshieldWipersSwitch#AUTO}).\r\n<p>If {@code #WINDSHIELD_WIPERS_STATE} = {@link\r\nandroid.car.hardware.property.WindshieldWipersState#ON} and {@link #WINDSHIELD_WIPERS_PERIOD}\r\nis implemented, then {@link #WINDSHIELD_WIPERS_PERIOD} will reflect the time period of 1\r\nfull cycle of the wipers.\r\n<p>For each supported area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.WindshieldWipersState} are supported.','google',1,'WindshieldWipersState',0,'2024-11-13 17:14:33','',0),(140,322964423,'WINDSHIELD_WIPERS_SWITCH','VEHICLE_AREA_TYPE_WINDOW','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','挡风玻璃刮水器开关。\r\n<p>表示控制挡风玻璃刮水器的开关的位置。价值\r\n{@code windshield_wipers_switch}可能与{@link #windshield_wipers_state}的值不匹配\r\n（例如{@code windshield_wipers_switch} = {@link\r\nandroid.car.hardware.property.windshieldwipersswitch＃auto}和{@link\r\n#windshield_wipers_state} = WindshieldWiperSstate＃on）。\r\n<p>对于每个受支持的区域ID，{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个值\r\n支持{@link android.car.hardware.property.windshieldwipersswitch}。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Windshield wipers switch.\r\n<p>Represents the position of the switch controlling the windshield wipers. The value of\r\n{@code WINDSHIELD_WIPERS_SWITCH} may not match the value of {@link #WINDSHIELD_WIPERS_STATE}\r\n(e.g. {@code WINDSHIELD_WIPERS_SWITCH} = {@link\r\nandroid.car.hardware.property.WindshieldWipersSwitch#AUTO} and {@link\r\n#WINDSHIELD_WIPERS_STATE} = WindshieldWipersState#ON).\r\n<p>For each supported area ID, the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which values\r\nfrom {@link android.car.hardware.property.WindshieldWipersSwitch} are supported.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'WindshieldWipersSwitch',0,'2024-11-13 17:14:33','',0),(141,289410016,'STEERING_WHEEL_DEPTH_POS','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘深度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示转向\r\n车轮最接近驾驶员时的位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}指示转向\r\n距离驾驶员最远时，车轮的位置。\r\n<p>支持最小值和最大值之间的所有整数，并表示过渡\r\n在最接近和最远的位置之间的状态。','Steering wheel depth position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the steering\r\nwheel\'s position when closest to the driver.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the steering\r\nwheel\'s position when farthest from the driver.\r\n<p>All integers in between the min and max values are supported and indicate a transition\r\nstate between the closest and farthest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(142,289410017,'STEERING_WHEEL_DEPTH_MOVE','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘深度运动。\r\n<p>返回速度和方向，无论是朝着驾驶员还是远离驾驶员，\r\n方向盘正在移动。此属性不在任何特定的单元中，而是在指定的\r\n相对运动速度的范围。\r\n<p>正值意味着方向盘正在远离驱动器和负值\r\n表示方向盘向驾驶员移动。较大的整数，要么积极或\r\n负，表示更快的速度。一旦方向盘达到位置极限，\r\n值重置为0。当此属性的值为0时，这意味着当前没有移动\r\n发生。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Steering wheel depth movement.\r\n<p>Returns the speed and direction, either towards or away from the driver, that the\r\nsteering wheel is moving in. This property is not in any particular unit but in a specified\r\nrange of relative movement speeds.\r\n<p>Positive values mean the steering wheel is moving away from the driver and negative values\r\nmean the steering wheel is moving towards the driver. Larger integers, either positive or\r\nnegative, indicate a faster speed. Once the steering wheel reaches the positional limit, the\r\nvalue resets to 0. When this property\'s value is 0, that means there is no movement currently\r\noccurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(143,289410018,'STEERING_WHEEL_HEIGHT_POS','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘高度位置。\r\n<p>此属性不在任何特定的单元中，而是在指定的相对范围内\r\n位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}指示转向\r\n车轮的最低位置。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}指示转向\r\n车轮的最高位置。\r\n<p>支持最小值和最大值之间的所有整数，并表示过渡\r\n在最低和最高位置之间的状态。','Steering wheel height position.\r\n<p>This property is not in any particular unit but in a specified range of relative\r\npositions.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} indicates the steering\r\nwheel\'s lowest position.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} indicates the steering\r\nwheel\'s highest position.\r\n<p>All integers in between the min and max values are supported and indicate a transition\r\nstate between the lowest and highest positions.','google',1,'',0,'2024-11-13 17:14:33','',0),(144,289410019,'STEERING_WHEEL_HEIGHT_MOVE','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘高度运动。\r\n<p>返回方向盘的速度和方向，向上或向下返回\r\n进入。此属性不在任何特定的单元中，而是在指定的相对范围内\r\n运动速度。\r\n<p>正值意味着向上移动，负值表示向下移动。更大\r\n整数（正或负数）表示更快的速度。一旦方向盘\r\n达到位置限制，值重置为0。当此属性的值为0时，\r\n意味着目前没有运动。\r\n<p>请参阅{@link android.car.hardware.property.areaidconfig＃getmaxvalue（）}}和{@link\r\nandroid.car.hardware.property.areaidConfig＃getMinvalue（）}可能的速度范围。\r\n支持最小值和最大值之间的所有整数。','Steering wheel height movement.\r\n<p>Returns the speed and direction, either upwards or downwards, that the steering wheel is\r\nmoving in. This property is not in any particular unit but in a specified range of relative\r\nmovement speeds.\r\n<p>Positive values mean moving upwards and negative values mean moving downwards. Larger\r\nintegers, either positive or negative, indicate a faster speed. Once the steering wheel\r\nreaches the positional limit, the value resets to 0. When this property\'s value is 0, that\r\nmeans there is no movement currently occurring.\r\n<p>See {@link android.car.hardware.property.AreaIdConfig#getMaxValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMinValue()} for the range of possible speeds.\r\nAll integers between min and max value are supported.','google',1,'',0,'2024-11-13 17:14:33','',0),(145,287312868,'STEERING_WHEEL_THEFT_LOCK_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘盗窃锁功能启用。\r\n<p>如果启用了方向盘盗窃锁定功能，则返回true\r\n禁用。如果启用，方向盘将自动锁定以防止盗窃\r\n某些情况。','Steering wheel theft lock feature enabled.\r\n<p>Returns true if the steering wheel theft lock feature is enabled and false if it is\r\ndisabled. If enabled, the steering wheel will lock automatically to prevent theft in\r\ncertain situations.','google',1,'',0,'2024-11-13 17:14:33','',0),(146,287312869,'STEERING_WHEEL_LOCKED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘锁定。\r\n<p>如果方向盘锁定，则返回true。如果锁定，方向盘的位置是\r\n不变。','Steering wheel locked.\r\n<p>Returns true if the steering wheel is locked. If locked, the steering wheel鈥檚 position is\r\nnot changeable.','google',1,'',0,'2024-11-13 17:14:33','',0),(147,287312870,'STEERING_WHEEL_EASY_ACCESS_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘易于访问功能启用。\r\n<p>如果启用了方向盘轻松访问功能，则返回tru\r\n禁用。如果启用，驾驶员的方向盘将自动调整以使其更容易\r\n让驾驶员进入并退出车辆。','Steering wheel easy access feature enabled.\r\n<p>Returns true if the steering wheel easy access feature is enabled and false if it is\r\ndisabled. If enabled, the driver鈥檚 steering wheel will automatically adjust to make it easier\r\nfor the driver to enter and exit the vehicle.','google',1,'',0,'2024-11-13 17:14:33','',0),(148,289410064,'LOCATION_CHARACTERIZATION','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','用于计算位置的输入的表征。\r\n<p>此属性指示系统考虑的数据和传感器输入（如果有）\r\n通过{@link计算与Android共享的车辆的位置时\r\nandroid.location.locationManager＃gps_provider}。\r\n<p>返回的值是位标志的集合。位标志在{@link中定义\r\n位置characterization}。该值也将完全包括\r\n{@link LocationCharacterization＃dead_reckoned}或{@link\r\n位置characterization＃raw_gnss_only}在其集合中\r\n位标志。\r\n<p>当不支持此属性时，假定没有其他传感器输入是\r\n融合到通过{@link提供的GNSS更新\r\nandroid.location.locationManager＃gps_provider}。除非另有说明\r\n其他{@link android.location.locationmanager} apis。','Characterization of inputs used for computing location.\r\n<p>This property indicates what (if any) data and sensor inputs are considered by the system\r\nwhen computing the vehicle\'s location that is shared with Android through {@link\r\nandroid.location.LocationManager#GPS_PROVIDER}.\r\n<p>The value returned is a collection of bit flags. The bit flags are defined in {@link\r\nLocationCharacterization}. The value will also include exactly\r\none of {@link LocationCharacterization#DEAD_RECKONED} or {@link\r\nLocationCharacterization#RAW_GNSS_ONLY} among its collection of\r\nbit flags.\r\n<p>When this property is not supported, it is assumed that no additional sensor inputs are\r\nfused into the GNSS updates provided through {@link\r\nandroid.location.LocationManager#GPS_PROVIDER}. That is unless otherwise specified through\r\nother {@link android.location.LocationManager} APIs.','google',1,'',0,'2024-11-13 17:14:33','',0),(149,406916128,'ULTRASONICS_SENSOR_POSITION','VEHICLE_AREA_TYPE_VENDOR','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','安装在车辆上的每个超声传感器位置的静态数据。\r\n<p>每个传感器都通过其唯一{@link apearIdConfig＃getAreaid（）}识别\r\n返回传感器的位置格式为[x，y，z]，其中：\r\n<ul>\r\n<li> x是沿x轴的位置相对于Android的起源\r\n毫米中的汽车传感器坐标框架。\r\n<li> y是沿Y轴的位置相对于Android的起源\r\n毫米中的汽车传感器坐标框架。\r\n<li> z是沿z轴相对于Android的起源的传感器的位置\r\n毫米中的汽车传感器坐标框架。\r\n</ul>','Static data for the position of each ultrasonic sensor installed on the vehicle.\r\n<p>Each individual sensor is identified by its unique {@link AreaIdConfig#getAreaId()} and\r\nreturns the sensor\'s position formatated as [x, y, z] where:\r\n<ul>\r\n <li>x is the position of the sensor along the x-axis relative to the origin of the Android\r\n Automotive sensor coordinate frame in millimeters.\r\n <li>y is the position of the sensor along the y-axis relative to the origin of the Android\r\n Automotive sensor coordinate frame in millimeters.\r\n <li>z is the position of the sensor along the z-axis relative to the origin of the Android\r\n Automotive sensor coordinate frame in millimeters.\r\n</ul>','google',1,'',0,'2024-11-13 17:14:33','',0),(150,409013281,'ULTRASONICS_SENSOR_ORIENTATION','VEHICLE_AREA_TYPE_VENDOR','Float[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','用于车辆上安装的每个超声传感器方向的静态数据。\r\n<p>每个传感器都由其{@link aideidconfig＃getareAid（）}识别并返回\r\n传感器的方向格式为[QW，QX，QY，QZ]，其中：\r\n<ul>\r\n<li> QW是Quaterinion中的四个系数W（W + XI + YJ + ZK）\r\n传感器相对于Android汽车传感器坐标框架的旋转。\r\n<li> Qx是四元素中的四个系数x（W + XI + YJ + ZK）\r\n传感器相对于Android汽车传感器坐标框架的旋转。\r\n<li> qy是四季度中的四元素系数y（W + XI + YJ + ZK）\r\n传感器相对于Android汽车传感器坐标框架的旋转。\r\n<li> qz是四季度中的四个系数z（W + XI + YJ + ZK）\r\n传感器相对于Android汽车传感器坐标框架的旋转。\r\n</ul>\r\n<p>这假设每个传感器都使用与Android汽车相同的轴约定。','Static data for the orientation of each ultrasonic sensor installed on the vehicle.\r\n<p>Each individual sensor is identified by its {@link AreaIdConfig#getAreaId()} and returns\r\nthe sensor\'s orientation formatted as [qw, qx, qy, qz] where:\r\n<ul>\r\n <li>qw is the quaternion coefficient w within the quaterinion (w + xi + yj + zk) describing\r\n the rotation of the sensor relative to the Android Automotive sensor coordinate frame.\r\n <li>qx is the quaternion coefficient x within the quaterinion (w + xi + yj + zk) describing\r\n the rotation of the sensor relative to the Android Automotive sensor coordinate frame.\r\n <li>qy is the quaternion coefficient y within the quaterinion (w + xi + yj + zk) describing\r\n the rotation of the sensor relative to the Android Automotive sensor coordinate frame.\r\n <li>qz is the quaternion coefficient z within the quaterinion (w + xi + yj + zk) describing\r\n the rotation of the sensor relative to the Android Automotive sensor coordinate frame.\r\n</ul>\r\n<p>This assumes each sensor uses the same axes conventions as Android Automotive.','google',1,'',0,'2024-11-13 17:14:33','',0),(151,406916130,'ULTRASONICS_SENSOR_FIELD_OF_VIEW','VEHICLE_AREA_TYPE_VENDOR','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','每个超声传感器视野的静态数据。\r\n<p>每个传感器都由其{@link aideidconfig＃getareAid（）}识别并返回\r\n传感器的视场格式为[水平，垂直]，其中：\r\n<ul>\r\n<li>水平是指定超声传感器的水平视场\r\n学位。\r\n<li>垂直是相关指定超声传感器的垂直视野\r\n学位。\r\n</ul>\r\n<p>这假设每个传感器都使用与Android汽车相同的轴约定。','Static data for the field of view of each ultrasonic sensor in degrees.\r\n<p>Each individual sensor is identified by its {@link AreaIdConfig#getAreaId()} and returns\r\nthe sensor\'s field of view formatted as [horizontal, vertical] where:\r\n<ul>\r\n <li>horizontal is the horizontal field of view for the specified ultrasonic sensor in\r\n degrees.\r\n <li>vertical is the vertical field of view for the associated specified ultrasonic sensor in\r\n degrees.\r\n</ul>\r\n<p>This assumes each sensor uses the same axes conventions as Android Automotive.','google',1,'',0,'2024-11-13 17:14:33','',0),(152,406916131,'ULTRASONICS_SENSOR_DETECTION_RANGE','VEHICLE_AREA_TYPE_VENDOR','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','毫米中每个超声传感器检测范围的静态数据。\r\n<p>每个传感器都由其{@link aideidconfig＃getareAid（）}识别并返回\r\n传感器的检测范围格式为[最小值，最大]，其中：\r\n<ul>\r\n<li>最小值是超声传感器在毫米中可检测到的最小范围。\r\n<li>最大值是毫米中超声传感器可检测到的最大范围。\r\n</ul>','Static data for the detection range of each ultrasonic sensor in millimeters.\r\n<p>Each individual sensor is identified by its {@link AreaIdConfig#getAreaId()} and returns\r\nthe sensor\'s detection range formatted as [minimum, maximum] where:\r\n<ul>\r\n <li>minimum is the minimum range detectable by the ultrasonic sensor in millimeters.\r\n <li>maximum is the maximum range detectable by the ultrasonic sensor in millimeters.\r\n</ul>','google',1,'',0,'2024-11-13 17:14:33','',0),(153,406916132,'ULTRASONICS_SENSOR_SUPPORTED_RANGES','VEHICLE_AREA_TYPE_VENDOR','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','毫米中每个超声传感器受支持范围的静态数据。\r\n<p>对于仅支持特定范围内读数的超声传感器。例如，如果\r\n超声波传感器以700mm的形式检测到对象，但只能报告对象已有\r\n检测到500mm至1000mm。\r\n<p>每个传感器都由其{@link aideidconfig＃getareAid（）}识别并返回\r\n传感器的支持范围格式为[range_min_1，range_max_1，range_min_2，\r\nrange_max_2，...]其中：\r\n<ul>\r\n<li> range_min_1是指定传感器的一个支持范围的最低\r\n毫米，包括。\r\n<li> range_max_1是指定传感器中一个支持范围的最大值\r\n毫米，包括。\r\n<li> range_min_2是由指定传感器在\r\n毫米，包括。\r\n<li> range_max_2是指定传感器的另一个支持范围的最大值\r\n毫米，包括。\r\n</ul>\r\n<p>例如，如果超声传感器支持150mm至499mm，500mm至999mm，则\r\n和1000mm至1500mm，然后将属性设置为：\r\n<ul>\r\n<li>值[0] = 150\r\n<li>值[1] = 499\r\n<li>值[2] = 500\r\n<li>值[3] = 999\r\n<li>值[4] = 1000\r\n<li>值[5] = 1500\r\n</ul>\r\n<p>如果未定义此属性，则\r\n{@link #ultrasonics_sensor_detection_range}用于指定的传感器为\r\n支持。','Static data for the supported ranges of each ultrasonic sensor in millimeters.\r\n<p>For ultrasonic sensors that only support readings within a specific range. For example, if\r\nan ultrasonic sensor detects an object at 700mm, but can only report that an object has been\r\ndetected between 500mm and 1000mm.\r\n<p>Each individual sensor is identified by its {@link AreaIdConfig#getAreaId()} and returns\r\nthe sensor\'s supported ranges formatted as [range_min_1, range_max_1, range_min_2,\r\nrange_max_2, ...] where:\r\n<ul>\r\n <li>range_min_1 is the minimum of one supported range by the specified sensor in\r\n millimeters, inclusive.\r\n <li>range_max_1 is the maximum of one supported range by the specified sensor in\r\n millimeters, inclusive.\r\n <li> range_min_2 is the minimum of another supported range by the specified sensor in\r\n millimeters, inclusive.\r\n <li> range_max_2 is the maximum of another supported range by the specified sensor in\r\n millimeters, inclusive.\r\n</ul>\r\n<p>For example, if an ultrasonic sensor supports the ranges 150mm to  499mm, 500mm to 999mm,\r\nand 1000mm to 1500mm, then the property should be set to:\r\n<ul>\r\n <li>value[0] = 150\r\n <li>value[1] = 499\r\n <li>value[2] = 500\r\n <li>value[3] = 999\r\n <li>value[4] = 1000\r\n <li>value[5] = 1500\r\n</ul>\r\n<p>If this property is not defined, all the values within the\r\n{@link #ULTRASONICS_SENSOR_DETECTION_RANGE} for the specified sensor are assumed to be\r\nsupported.','google',1,'',0,'2024-11-13 17:14:33','',0),(154,406916133,'ULTRASONICS_SENSOR_MEASURED_DISTANCE','VEHICLE_AREA_TYPE_VENDOR','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','每毫米中每个传感器最近检测到的对象的距离读数。\r\n<p>每个传感器都由其{@link aideidconfig＃getareAid（）}识别并返回\r\n传感器的测量距离格式为[距离，decand_error]，其中：\r\n<ul>\r\n<li>距离是毫米中最近对象的测量距离。如果只有一个范围\r\n受支持，该值必须设置为检测到的最小支持距离\r\n如{@link #ultrasonics_sensor_supported_ranges}中指定。\r\n<li> decond_error是毫米中测得的距离值的误差。\r\n</ul>\r\n<p>如果未检测到对象，则将返回一个空的向量。如果decand_error不是\r\n可用，然后仅返回一个测量距离的数组。','The distance reading of the nearest detected object per sensor in millimeters.\r\n<p>Each individual sensor is identified by its {@link AreaIdConfig#getAreaId()} and returns\r\nthe sensor\'s measured distance formatted as [distance, distance_error] where:\r\n<ul>\r\n <li>distance is the measured distance of the nearest object in millimeters. If only a range\r\n is supported, this value must be set to the minimum supported distance in the detected range\r\n as specified in {@link #ULTRASONICS_SENSOR_SUPPORTED_RANGES}.\r\n <li>distance_error is the error of the measured distance value in millimeters.\r\n</ul>\r\n<p>If no object is detected, an empty vector will be returned. If distance_error is not\r\navailable then an array of only the measured distance will be returned.','google',1,'',0,'2024-11-13 17:14:33','',0),(155,289410560,'HEADLIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','大灯状态。','Headlights State.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(156,289410561,'HIGH_BEAM_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','远光灯状态。','High beam lights state.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(157,289410562,'FOG_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','雾光状态。\r\n<p>如果汽车具有前和后雾灯：\r\n<ul>\r\n<li>如果只能一起控制前和后雾灯：{@code fog_lights_state}\r\n提供雾灯的状态。\r\n<li>如果前后雾灯只能独立控制：{@link\r\n#FRONT_FOG_LIGHTS_STATE}和{@link #Rear_Fog_lights_state}提供前，后方的状态\r\n雾灯分别。\r\n</ul>\r\n<p>如果汽车只有前雾灯：\r\n<ul>\r\n<li> {@code fog_lights_state}或{@link #front_fog_lights_state}中只有一个\r\n在汽车中实施。实施的属性提供了前雾灯的状态。\r\n</ul>\r\n<p>如果汽车只有后雾灯：\r\n<ul>\r\n<li> {@code fog_lights_state}或{@link #rear_fog_lights_state}中只有一个\r\n在汽车中实施。实施的属性提供后雾灯的状态。\r\n</ul>','Fog light state.\r\n<p>If the car has both front and rear fog lights:\r\n<ul>\r\n <li>If front and rear fog lights can only be controlled together: {@code FOG_LIGHTS_STATE}\r\n provides the state of fog lights.\r\n <li>If front and rear fog lights can only be controlled independently: {@link\r\n #FRONT_FOG_LIGHTS_STATE} and {@link #REAR_FOG_LIGHTS_STATE} provide the state of front, rear\r\n fog lights respectively.\r\n</ul>\r\n<p>If the car has only front fog lights:\r\n<ul>\r\n <li>Only one of {@code FOG_LIGHTS_STATE} or {@link #FRONT_FOG_LIGHTS_STATE} will be\r\n implemented in the car. The implemented property provides the state of the front fog lights.\r\n</ul>\r\n<p>If the car has only rear fog lights:\r\n<ul>\r\n <li>Only one of {@code FOG_LIGHTS_STATE} or {@link #REAR_FOG_LIGHTS_STATE} will be\r\n implemented in the car. The implemented property provides the state of the rear fog lights.\r\n</ul>','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(158,289410563,'HAZARD_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','危险光状态。','Hazard light status.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(159,289410576,'HEADLIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','大灯开关。','Headlight switch.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(160,289410577,'HIGH_BEAM_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','远光灯开关。','High beam light switch.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(161,289410578,'FOG_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','雾灯开关。\r\n<p>如果汽车具有前和后雾灯：\r\n<ul>\r\n<li>如果只能将前雾灯和后雾灯一起控制：{@code fog_lights_switch}\r\n应用来更改雾灯状态。\r\n<li>如果前后雾灯只能独立控制：{@link\r\n#front_fog_lights_switch}和{@link #rear_fog_lights_switch}应用于更改\r\n前后雾灯分别为状态。\r\n</ul>\r\n<p>如果汽车只有前雾灯：\r\n<ul>\r\n<li> {@code fog_lights_switch}或{@link #front_fog_lights_switch}中只有一个\r\n在汽车中实施。实施的属性应用于更改前雾\r\n灯状态。\r\n</ul>\r\n<p>如果汽车只有后雾灯：\r\n<ul>\r\n<li> {@code fog_lights_switch}或{@link #rear_fog_lights_switch}中只有一个\r\n在汽车中实施。实施的属性应用于更改后雾\r\n灯状态。\r\n</ul>','Fog light switch.\r\n<p>If the car has both front and rear fog lights:\r\n<ul>\r\n <li>If front and rear fog lights can only be controlled together: {@code FOG_LIGHTS_SWITCH}\r\n should be used to change the fog lights state.\r\n <li>If front and rear fog lights can only be controlled independently: {@link\r\n #FRONT_FOG_LIGHTS_SWITCH} and {@link #REAR_FOG_LIGHTS_SWITCH} should be used to change the\r\n front and rear fog lights state respectively.\r\n</ul>\r\n<p>If the car has only front fog lights:\r\n<ul>\r\n <li>Only one of {@code FOG_LIGHTS_SWITCH} or {@link #FRONT_FOG_LIGHTS_SWITCH} will be\r\n implemented in the car. The implemented property should be used to change the front fog\r\n lights state.\r\n</ul>\r\n<p>If the car has only rear fog lights:\r\n<ul>\r\n <li>Only one of {@code FOG_LIGHTS_SWITCH} or {@link #REAR_FOG_LIGHTS_SWITCH} will be\r\n implemented in the car. The implemented property should be used to change the rear fog\r\n lights state.\r\n</ul>','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(162,289410579,'HAZARD_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','危险照明开关。','Hazard light switch.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(163,289410817,'CABIN_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','机舱灯。','Cabin lights.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(164,289410818,'CABIN_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','机舱灯开关。','Cabin lights switch.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(165,356519683,'READING_LIGHTS_STATE','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','阅读灯。','Reading lights.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(166,356519684,'READING_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_SEAT','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','阅读灯开关。','Reading lights switch.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(167,289410828,'STEERING_WHEEL_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘灯状态。\r\n<p>返回方向盘灯的当前状态。这与{@link不同\r\n#steering_wheel_lights_switch}代表开关控制的位置\r\n灯。因此，{@code steering_wheel_lights_state}可能与\r\n{@link #steering_wheel_lights_switch}（例如{@link #steering_wheel_lights_switch} = {@code\r\nvericlelightswitch＃state_automatic}和{@code steering_wheel_lights_state} = {@code\r\nvericlelightState＃state_on}）。\r\n<p>仅当{@code steering_wheel_lights_state}的值可能才能实现此属性\r\n与{@link #cabin_lights_state}不同。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getsupportedenumvalues（）}从{@link获得\r\nandroid.car.hardware.carpropertyconfig＃getAreAidConfig（int）}指定从\r\n{@code vericlelightstate}得到了支持。','Steering wheel lights state.\r\n<p>Returns the current state of the steering wheel lights. This is different from {@link\r\n#STEERING_WHEEL_LIGHTS_SWITCH} which represents the position of the switch controlling\r\nthe lights. Therefore, {@code STEERING_WHEEL_LIGHTS_STATE} may not match the value of\r\n{@link #STEERING_WHEEL_LIGHTS_SWITCH} (e.g. {@link #STEERING_WHEEL_LIGHTS_SWITCH}={@code\r\nVehicleLightSwitch#STATE_AUTOMATIC} and {@code STEERING_WHEEL_LIGHTS_STATE}={@code\r\nVehicleLightState#STATE_ON}).\r\n<p>This property will only be implemented if {@code STEERING_WHEEL_LIGHTS_STATE}\'s value may\r\nbe different from that of {@link #CABIN_LIGHTS_STATE}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} obtained from {@link\r\nandroid.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum values from\r\n{@code VehicleLightState} are supported.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(168,289410829,'STEERING_WHEEL_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','方向盘灯开关。\r\n<p>返回控制方向盘灯的开关的位置。这是\r\n不同于{@link #steering_wheel_lights_state}代表当前状态\r\n方向盘灯。因此，{@code steering_wheel_lights_switch}可能与\r\n{@link #steering_wheel_lights_state}的值\r\n{@code vericlelightswitch＃state_automatic}和{@link #steering_wheel_lights_state} = {@code\r\nvericlelightState＃state_on}）。\r\n<p>仅当{@code steering_wheel_lights_switch}的值可能才能实现此属性\r\n与{@link #cabin_lights_switch}不同。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getsupportedenumvalues（）}从{@link获得\r\nandroid.car.hardware.carpropertyconfig＃getAreAidConfig（int）}指定从\r\n{@code vericlelightswitch}得到了支持。','Steering wheel lights switch.\r\n<p>Returns the position of the switch controlling the steering wheel lights. This is\r\ndifferent from {@link #STEERING_WHEEL_LIGHTS_STATE} which represents the current state of the\r\nsteering wheel lights. Therefore, {@code STEERING_WHEEL_LIGHTS_SWITCH} may not match the\r\nvalue of {@link #STEERING_WHEEL_LIGHTS_STATE} (e.g. {@code STEERING_WHEEL_LIGHTS_SWITCH}=\r\n{@code VehicleLightSwitch#STATE_AUTOMATIC} and {@link #STEERING_WHEEL_LIGHTS_STATE}={@code\r\nVehicleLightState#STATE_ON}).\r\n<p>This property will only be implemented if {@code STEERING_WHEEL_LIGHTS_SWITCH}\'s value may\r\nbe different from that of {@link #CABIN_LIGHTS_SWITCH}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} obtained from {@link\r\nandroid.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum values from\r\n{@code VehicleLightSwitch} are supported.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(169,299896583,'INITIAL_USER_INFO','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','属性以获取用于多用户管理的初始设置（例如初始用户）。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to get the initial settings for multi-user management (such as initial user).\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(170,299896584,'SWITCH_USER','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','用于切换用户进行多用户管理的属性。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to switch user for multi-user management.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(171,299896585,'CREATE_USER','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','属性创建用于多用户管理的新用户。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to create a new user for multi-user management.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(172,299896586,'REMOVE_USER','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','属性以删除用于多用户管理的新用户。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to remove a new user for multi-user management.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(173,299896587,'USER_IDENTIFICATION_ASSOCIATION','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','获取 /设置与Android用户关联的用户身份验证类型的属性。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to get / set the user authentication types associated with an Android user.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(174,286265121,'POWER_POLICY_REQ','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','VHAL应用权力政策的财产。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property for VHAL to apply power policy.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(175,286265122,'POWER_POLICY_GROUP_REQ','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','VHAL的属性设置每个功率状态过渡的默认电源策略。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property for VHAL to set the default power policies per power status transition.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(176,286265123,'CURRENT_POWER_POLICY','VEHICLE_AREA_TYPE_GLOBAL','String','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','向Vhal报告新的当前电力政策的财产。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to report a new current power policy to VHAL.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(177,290459441,'WATCHDOG_ALIVE','VEHICLE_AREA_TYPE_GLOBAL','Long','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','报告说汽车监管机构还活着的财产。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to report that car watchdog is alive.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(178,299896626,'WATCHDOG_TERMINATED_PROCESS','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','财产报告由汽车监管机终止的过程。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to report a process terminated by car watchdog.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(179,290459443,'VHAL_HEARTBEAT','VEHICLE_AREA_TYPE_GLOBAL','Long','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','属性，向Vhal发出心跳信号。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to signal a heartbeat from VHAL.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(180,289410868,'CLUSTER_SWITCH_UI','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','在群集显示中启动clusterui的属性。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to start the ClusterUI in cluster display.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(181,289476405,'CLUSTER_DISPLAY_STATE','VEHICLE_AREA_TYPE_GLOBAL','Integer[]','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','更改群集显示状态的属性。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to change the state of the cluster display.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(182,299896630,'CLUSTER_REPORT_STATE','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','属性要报告当前显示和clusterui雕像。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to reports the current display and ClusterUI statue.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(183,289410871,'CLUSTER_REQUEST_DISPLAY','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','要更改群集显示状态以显示某些群集>不需要许可的属性，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to request to change the cluster display state to show some ClusterUI.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(184,292556600,'CLUSTER_NAVIGATION_STATE','VEHICLE_AREA_TYPE_GLOBAL','bytes[]','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','通知当前导航状态的财产。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to inform the current navigation state.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(185,299896651,'CLUSTER_HEARTBEAT','VEHICLE_AREA_TYPE_GLOBAL','Object[]','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','属性将心跳信号发送到clusteros。\r\n<p>不需要许可，因为它没有通过\r\n{@link android.car.hardware.property.carpropertymanager}。','Property to send the heartbeat signal to ClusterOS.\r\n<p>Doesn\'t require permission because it\'s not exposed through\r\n{@link android.car.hardware.property.CarPropertyManager}.','google',1,'',0,'2024-11-13 17:14:33','',0),(186,290457094,'EPOCH_TIME','VEHICLE_AREA_TYPE_GLOBAL','Long','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','当前日期和时间，编码为UNIX时间。\r\n<p>此值表示自1970年1月1日UTC以来已经过去的毫秒数。','Current date and time, encoded as Unix time.\r\n<p>This value denotes the number of milliseconds that have elapsed since 1/1/1970 UTC.','google',1,'',0,'2024-11-13 17:14:33','',0),(187,289410873,'ELECTRONIC_TOLL_COLLECTION_CARD_TYPE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电子收费卡类型。\r\n<p>此属性指示车辆中的ETC类型（电子收费）卡的类型。\r\n如果主机知道车辆附加了ETC卡，则该属性应返回\r\n附有卡的类型；否则，该属性不应不可用。属性值\r\n应该是{@link wallelectRonictoltCollectionCardType}之一。','Electronic Toll Collection card type.\r\n<p>This property indicates the type of ETC(Electronic Toll Collection) card in the vehicle.\r\nIf the head unit is aware of an ETC card attached to the vehicle, this property should return\r\nthe type of card attached; otherwise, this property should be UNAVAILABLE. The property value\r\nshould be one of {@link VehicleElectronicTollCollectionCardType}.','google',1,'VehicleElectronicTollCollectionCardType',0,'2024-11-13 17:14:33','',0),(188,289410874,'ELECTRONIC_TOLL_COLLECTION_CARD_STATUS','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','电子收费卡状态。\r\n<p>此属性指示车辆中ETC（电子通行费收集）卡的状态。\r\n如果主机知道车辆附加了ETC卡，etc_card_status给出了\r\n卡的状态；否则，该属性不应不可用。属性值应\r\n成为{@link wallelectRonictOlcollectionCardStatus}之一。','Electronic Toll Collection card status.\r\n<p>This property indicates the status of ETC(Electronic Toll Collection) card in the vehicle.\r\nIf the head unit is aware of an ETC card attached to the vehicle, ETC_CARD_STATUS gives that\r\nstatus of the card; otherwise, this property should be UNAVAILABLE. The property value should\r\nbe one of {@link VehicleElectronicTollCollectionCardStatus}.','google',1,'VehicleElectronicTollCollectionCardStatus',0,'2024-11-13 17:14:33','',0),(189,289410875,'FRONT_FOG_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','前雾灯状态。\r\n<p>请参阅{@link #fog_lights_state}上的文档以获取更多信息。','Front fog lights state.\r\n<p>Please refer to the documentation on {@link #FOG_LIGHTS_STATE} for more information.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(190,289410876,'FRONT_FOG_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','前雾灯开关。\r\n<p>请参阅{@link #fog_lights_switch}上的文档以获取更多信息。','Front fog lights switch.\r\n<p>Please refer to the documentation on {@link #FOG_LIGHTS_SWITCH} for more information.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(191,289410877,'REAR_FOG_LIGHTS_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','后雾灯状态。\r\n<p>请参阅{@link #fog_lights_state}上的文档以获取更多信息。','Rear fog lights state.\r\n<p>Please refer to the documentation on {@link #FOG_LIGHTS_STATE} for more information.','google',1,'VehicleLightState',0,'2024-11-13 17:14:33','',0),(192,289410878,'REAR_FOG_LIGHTS_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','后雾灯开关。\r\n<p>请参阅{@link #fog_lights_switch}上的文档以获取更多信息。','Rear fog lights switch.\r\n<p>Please refer to the documentation on {@link #FOG_LIGHTS_SWITCH} for more information.','google',1,'VehicleLightSwitch',0,'2024-11-13 17:14:33','',0),(193,291508031,'EV_CHARGE_CURRENT_DRAW_LIMIT','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','EV充电当前抽奖限制。\r\n<p>指示用户设置的充电的最大电流拉动阈值。{@代码\r\nconfigarray [0]}包含车辆在安培中允许的最大电流抽奖。','EV charge current draw limit.\r\n<p>Indicates the maximum current draw threshold for charging set by the user. {@code\r\nconfigArray[0]} contains the max current draw allowed by the vehicle in Amperes.','google',1,'',0,'2024-11-13 17:14:33','',0),(194,291508032,'EV_CHARGE_PERCENT_LIMIT','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','EV充电百分比限制。\r\n<p>表示用户设置的最大充电百分比阈值。返回浮点值\r\n从0到100。\r\n<p>配置是可选的。如果填充了，则表示有效的充电百分比限制\r\n车辆的值。这是一个示例configarray：\r\n<ul>\r\n<li> configarray [0] = 20\r\n<li> configarray [1] = 40\r\n<li> configarray [2] = 60\r\n<li> configarray [3] = 80\r\n</ul>','EV charge percent limit.\r\n<p>Indicates the maximum charge percent threshold set by the user. Returns a float value\r\nfrom 0 to 100.\r\n<p>configArray is optional. If it is populated, it represents the valid charge percent limit\r\nvalues for the vehicle. Here is an example configArray:\r\n<ul>\r\n <li>configArray[0] = 20\r\n <li>configArray[1] = 40\r\n <li>configArray[2] = 60\r\n <li>configArray[3] = 80\r\n</ul>','google',1,'',0,'2024-11-13 17:14:33','',0),(195,289410881,'EV_CHARGE_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','充电汽车。\r\n<p>返回汽车当前的充电状态。请参阅{@link\r\nAndroid.car.hardware.property.evchargentate}对于{@Code EV_CHARGE_STATE}的可能值。\r\n<p>如果车辆的目标充电百分比以外的100个，则该属性将返回\r\n{@link evcharestate＃state_ly_charged}电池充电级别到达\r\n目标水平。有关更多上下文，请参见{@link #ev_charge_percent_limit}。','Charging state of the car.\r\n<p>Returns the current charging state of the car. See {@link\r\nandroid.car.hardware.property.EvChargeState} for possible values for {@code EV_CHARGE_STATE}.\r\n<p>If the vehicle has a target charge percentage other than 100, this property will return\r\n{@link EvChargeState#STATE_FULLY_CHARGED} when the battery charge level has reached the\r\ntarget level. See {@link #EV_CHARGE_PERCENT_LIMIT} for more context.','google',1,'EvChargeState',0,'2024-11-13 17:14:33','',0),(196,287313730,'EV_CHARGE_SWITCH','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启动或停止为电动汽车电池充电。\r\n<p>用户想要的设置。将此属性设置为TRUE启动电池充电\r\n并设置为虚假停止充电。','Start or stop charging the EV battery.\r\n<p>The setting that the user wants. Setting this property to true starts the battery charging\r\nand setting to false stops charging.','google',1,'',0,'2024-11-13 17:14:33','',0),(197,289410883,'EV_CHARGE_TIME_REMAINING','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','估计的充电时间在几秒钟内。\r\n<p>如果车辆未充电，则返回0。','Estimated charge time remaining in seconds.\r\n<p>Returns 0 if the vehicle is not charging.','google',1,'',0,'2024-11-13 17:14:33','',0),(198,289410884,'EV_REGENERATIVE_BRAKING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','汽车上的再生制动或一型驾驶设置。\r\n<p>返回与再生制动相关的当前状态\r\n在车里设置。请参阅{@link android.car.hardware.property.evregenerativebrakingstate}\r\n{@Code ev_regenerative_braking_state}的可能值。\r\n<p>如果已实现{@link #ev_brake_regeneration_level}属性，则可能是\r\nOEM支持比此提供的更精细的再生水平\r\n通过{@link evenerativeBrakingstate}属性。','Regenerative braking or one-pedal drive setting on the car.\r\n<p>Returns the current state associated with the regenerative braking\r\nsetting in the car. See {@link android.car.hardware.property.EvRegenerativeBrakingState} for\r\npossible values for {@code EV_REGENERATIVE_BRAKING_STATE}.\r\n<p>If the {@link #EV_BRAKE_REGENERATION_LEVEL} property has been implemented, it is likely\r\nthat the OEM supports a more granular set of regeneration levels than those provided by this\r\nproperty through {@link EvRegenerativeBrakingState}.','google',1,'EvRegenerativeBrakingState',0,'2024-11-13 17:14:33','',0),(199,289410886,'VEHICLE_CURB_WEIGHT','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','车辆的遏制重量为千克。\r\n<p>将车辆的路缘重量以千克返回。这是车辆的总重量，\r\n包括标准设备和必要的操作流体，例如机油，\r\n传输油和制动液，但没有乘客或货物。Configarray [0]指定\r\n车辆的重量为千克。这是车辆遏制重量加上最大的重量\r\n有效载荷（乘客 +货物）车辆可以支撑。','Vehicle鈥檚 curb weight in kilograms.\r\n<p>Returns the vehicle\'s curb weight in kilograms. This is the total weight of a vehicle,\r\ninclusive of standard equipment and necessary operating fluids such as motor oil,\r\ntransmission oil and brake fluid, but without passengers or cargo. configArray[0] specifies\r\nthe vehicle鈥檚 gross weight in kilograms. This is the vehicle curb weight plus the maximum\r\npayload (passengers + cargo) the vehicle can support.','google',1,'',0,'2024-11-13 17:14:33','',0),(200,289410885,'TRAILER_PRESENT','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','指示是否存在拖车。\r\n<p>返回汽车的拖车状态。有关可能的值\r\n{@Code Trailer_present}。','Indicates if there is a trailer present or not.\r\n<p>Returns the trailer state of the car. See {@code TrailerState} for possible values for\r\n{@code TRAILER_PRESENT}.','google',1,'TrailerState',0,'2024-11-13 17:14:33','',0),(201,289410887,'GENERAL_SAFETY_REGULATION_COMPLIANCE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_STATIC','欧盟的一般安全法规合规性要求。\r\n<p>返回是否需要一般安全法规合规性，如果\r\n因此，什么类型的要求。有关可能的枚举，请参见{@link gsrcompliancetype}。','EU\'s General security regulation compliance requirement.\r\n<p>Returns whether general security regulation compliance is required, if\r\nso, what type of requirement. See {@link GsrComplianceType} for possible enums.','google',1,'GsrComplianceType',0,'2024-11-13 17:14:33','',0),(202,289410892,'VEHICLE_DRIVING_AUTOMATION_CURRENT_LEVEL','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','当前的车辆自治状态。\r\n<p>定义了当前从SAE标准参与车辆的自主权水平\r\n级别0-5，0代表无自治，5代表完全驾驶自动化。这些\r\n级别是根据设定的标准定义的\r\n<a href =“ https://www.sae.org/standards/content/j3016_202104/”> J3016_202104修订版</a>\r\nSAE自动化水平分类及其对国际受众的澄清\r\n<a href =“ https://www.sae.org/blog/sae-j3016-update”>在这里</a>。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n从{@link android.car.hardware.property.vehicleautonomousousstate}中得到支持。','Current state of vehicle autonomy.\r\n<p>Defines the level of autonomy currently engaged in the vehicle from the SAE standard\r\nlevels 0-5, with 0 representing no autonomy and 5 representing full driving automation. These\r\nlevels are defined in accordance with the standards set in the\r\n<a href=\"\"https://www.sae.org/standards/content/j3016_202104/\"\">J3016_202104 revision</a> of\r\nthe SAE automation level taxonomy and its clarification for international audiences\r\n<a href=\"\"https://www.sae.org/blog/sae-j3016-update\"\">here</a>.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.VehicleAutonomousState} are supported.','google',1,'android.car.hardware.property.VehicleAutonomousState',0,'2024-11-13 17:14:33','',0),(203,287313920,'AUTOMATIC_EMERGENCY_BRAKING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用自动紧急制动（AEB）。\r\n<p>如果启用了AEB，则返回true，如果禁用AEB，则false。启用AEB时，ADA\r\n车辆中的系统应打开并进行监视，以避免潜在的碰撞。这\r\n属性仅适用于更高速度应用。用于启用低速自动\r\n紧急制动，{@link Low_speed_automatic_emergency_braking_enabled}将使用。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Automatic Emergency Braking (AEB).\r\n<p>Returns true if AEB is enabled and false if AEB is disabled. When AEB is enabled, the ADAS\r\nsystem in the vehicle should be turned on and monitoring to avoid potential collisions. This\r\nproperty applies for higher speed applications only. For enabling low speed automatic\r\nemergency braking, {@link LOW_SPEED_AUTOMATIC_EMERGENCY_BRAKING_ENABLED} will be used.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(204,289411073,'AUTOMATIC_EMERGENCY_BRAKING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','自动紧急制动（AEB）状态。\r\n<p>返回AEB的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.automaticemergencybrakingstate}或{@link\r\nandroid.car.hardware.property.errorstate}。该属性应申请更高的速度\r\n仅申请。代表低速自动紧急制动状态\r\n系统，{@link low_speed_automatic_emergency_braking_state}应使用。\r\n<p>如果AEB在激活刹车之前包括前碰撞警告，那些警告\r\n将通过前碰撞警告（FCW）属性浮出水面。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.automaticemergencybrakingstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Automatic Emergency Braking (AEB) state.\r\n<p>Returns the current state of AEB. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.AutomaticEmergencyBrakingState} or {@link\r\nandroid.car.hardware.property.ErrorState}. This property should apply for higher speed\r\napplications only. For representing the state of the low speed automatic emergency braking\r\nsystem, {@link LOW_SPEED_AUTOMATIC_EMERGENCY_BRAKING_STATE} should be used.\r\n<p>If AEB includes forward collision warnings before activating the brakes, those warnings\r\nwill be surfaced through the Forward Collision Warning (FCW) properties.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.AutomaticEmergencyBrakingState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'AutomaticEmergencyBrakingState|ErrorState',0,'2024-11-13 17:14:33','',0),(205,287313922,'FORWARD_COLLISION_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用前向碰撞警告（FCW）。\r\n<p>如果启用了FCW，则返回true，如果禁用FCW，则返回false。启用FCW时，ADA\r\n车辆中的系统应打开并监视潜在的碰撞。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Forward Collision Warning (FCW).\r\n<p>Returns true if FCW is enabled and false if FCW is disabled. When FCW is enabled, the ADAS\r\nsystem in the vehicle should be turned on and monitoring for potential collisions.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(206,289411075,'FORWARD_COLLISION_WARNING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','前碰撞警告状态（FCW）状态。\r\n<p>返回FCW的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.forwardCollisionWarningState}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.forwardCollisionWarningState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Forward Collision Warning State (FCW) state.\r\n<p>Returns the current state of FCW. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.ForwardCollisionWarningState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.ForwardCollisionWarningState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'ForwardCollisionWarningState|ErrorState',0,'2024-11-13 17:14:33','',0),(207,287313924,'BLIND_SPOT_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用和禁用盲点警告（BSW）。\r\n<p>如果启用了BSW，则返回true，如果禁用BSW，则返回false。启用BSW时，ADA\r\n车辆中的系统应打开并监视车辆中的物体 - 盲人\r\n斑点。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable and disable Blind Spot Warning (BSW).\r\n<p>Returns true if BSW is enabled and false if BSW is disabled. When BSW is enabled, the ADAS\r\nsystem in the vehicle should be turned on and monitoring for objects in the vehicle鈥檚 blind\r\nspots.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(208,339742725,'BLIND_SPOT_WARNING_STATE','VEHICLE_AREA_TYPE_MIRROR','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','盲点警告（BSW）状态。\r\n<p>返回BSW的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.blindspotwarningstate}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.blindspotwarningstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Blind Spot Warning (BSW) state.\r\n<p>Returns the current state of BSW. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.BlindSpotWarningState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.BlindSpotWarningState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'BlindSpotWarningState|ErrorState',0,'2024-11-13 17:14:33','',0),(209,287313926,'LANE_DEPARTURE_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用车道出发警告（LDW）。\r\n<p>如果启用了LDW，则返回true，如果禁用LDW，则返回false。启用LDW时，ADA\r\n车辆中的系统应打开并监视，如果车辆接近或\r\n越过车道线，在这种情况下将发出警告。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Lane Departure Warning (LDW).\r\n<p>Returns true if LDW is enabled and false if LDW is disabled. When LDW is enabled, the ADAS\r\nsystem in the vehicle should be turned on and monitoring if the vehicle is approaching or\r\ncrossing lane lines, in which case a warning will be given.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(210,289411079,'LANE_DEPARTURE_WARNING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车道出发警告（LDW）州。\r\n<p>返回LDW的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.lanedeparturewarningstate}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.lanedeparturewarningstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Lane Departure Warning (LDW) state.\r\n<p>Returns the current state of LDW. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.LaneDepartureWarningState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.LaneDepartureWarningState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'LaneDepartureWarningState|ErrorState',0,'2024-11-13 17:14:33','',0),(211,287313928,'LANE_KEEP_ASSIST_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用巷道助攻（LKA）。\r\n<p>如果启用LKA，则返回true，如果禁用LKA，则返回。启用LKA时，ADA\r\n如果驾驶员无意间漂移，则应打开车辆中的系统并监视\r\n朝向或越过车道标记。如果检测到无意的车道出发，系统\r\n应用转向控件以将车辆返回到当前车道。\r\n<p>这与泳道中心辅助（LCA）不同，该辅助（LCA）适用时，\r\n连续转向控制，以使车辆以当前车道为中心。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Lane Keep Assist (LKA).\r\n<p>Returns true if LKA is enabled and false if LKA is disabled. When LKA is enabled, the ADAS\r\nsystem in the vehicle should be turned on and monitoring if the driver unintentionally drifts\r\ntoward or over the lane marking. If an unintentional lane departure is detected, the system\r\napplies steering control to return the vehicle into the current lane.\r\n<p>This is different from Lane Centering Assist (LCA) which, when activated, applies\r\ncontinuous steering control to keep the vehicle centered in the current lane.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(212,289411081,'LANE_KEEP_ASSIST_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车道保持辅助（LKA）状态。\r\n<p>返回LKA的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.lanekeepassiststate}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果LKA在应用转向校正之前包括车道出发警告，\r\n警告将通过{@link #lane_departure_warning_state}浮出水面。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.lanekeepassiststate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Lane Keep Assist (LKA) state.\r\n<p>Returns the current state of LKA. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.LaneKeepAssistState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If LKA includes lane departure warnings before applying steering corrections, those\r\nwarnings will be surfaced through {@link #LANE_DEPARTURE_WARNING_STATE}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.LaneKeepAssistState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'LaneKeepAssistState|ErrorState',0,'2024-11-13 17:14:33','',0),(213,287313930,'LANE_CENTERING_ASSIST_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用车道中心辅助（LCA）。\r\n<p>如果启用LCA，则返回true，如果LCA被禁用，则返回false。启用LCA时，ADA\r\n车辆中的系统应打开并等待来自\r\n司机。一旦激活该功能，ADAS系统应转向车辆以保持\r\n它以当前车道为中心。\r\n<p>这与Lane Keep Assiss（LKA）不同，如果无意中监视驾驶员\r\n向沿车道标记漂移或越过。如果检测到无意的车道出发，\r\n系统应用转向控件将车辆返回到当前车道。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Lane Centering Assist (LCA).\r\n<p>Returns true if LCA is enabled and false if LCA is disabled. When LCA is enabled, the ADAS\r\nsystem in the vehicle should be turned on and waiting for an activation signal from the\r\ndriver. Once the feature is activated, the ADAS system should be steering the vehicle to keep\r\nit centered in its current lane.\r\n<p>This is different from Lane Keep Assist (LKA) which monitors if the driver unintentionally\r\ndrifts toward or over the lane marking. If an unintentional lane departure is detected, the\r\nsystem applies steering control to return the vehicle into the current lane.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(214,289411083,'LANE_CENTERING_ASSIST_COMMAND','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车道中心辅助（LCA）命令。\r\n<p>命令激活和暂停LCA。它们仅在{@link时才有效\r\n#lane_centering_assist_enabled} = {@code true}。否则，这些命令将投掷{@link\r\nandroid.car.hardware.property.propertynotavailableException}。\r\n<p>当命令{@link android.car.hardware.property.lanecenteringassistCommand＃activate}\r\n发送，{@link #lane_centering_assist_state}将设置为{@link\r\nandroid.car.hardware.property.lanecenteringAssistState＃activation_requested}。什么时候\r\n命令{@link android.car.hardware.property.lanecenteringassistCommand＃activate}成功，\r\n{@link #lane_centering_assist_state}将设置为{@link\r\nandroid.car.hardware.property.lanecenteringassstate＃activated}。当命令{@link\r\nandroid.car.hardware.property.lanecenteringassistCommand＃deactivate}成功，{@link\r\n#lane_centering_assist_state}将设置为{@link\r\nandroid.car.hardware.property.lanecenteringAssistState＃已启用}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定枚举\r\n支持{@link android.car.hardware.property.lanecenteringassistCommand}的值。','Lane Centering Assist (LCA) commands.\r\n<p>Commands to activate and suspend LCA. They are only valid when {@link\r\n#LANE_CENTERING_ASSIST_ENABLED} = {@code true}. Otherwise, these commands will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.\r\n<p>When the command {@link android.car.hardware.property.LaneCenteringAssistCommand#ACTIVATE}\r\nis sent, {@link #LANE_CENTERING_ASSIST_STATE} will be set to {@link\r\nandroid.car.hardware.property.LaneCenteringAssistState#ACTIVATION_REQUESTED}. When the\r\ncommand {@link android.car.hardware.property.LaneCenteringAssistCommand#ACTIVATE} succeeds,\r\n{@link #LANE_CENTERING_ASSIST_STATE} will be set to {@link\r\nandroid.car.hardware.property.LaneCenteringAssistState#ACTIVATED}. When the command {@link\r\nandroid.car.hardware.property.LaneCenteringAssistCommand#DEACTIVATE} succeeds, {@link\r\n#LANE_CENTERING_ASSIST_STATE} will be set to {@link\r\nandroid.car.hardware.property.LaneCenteringAssistState#ENABLED}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which enum\r\nvalues from {@link android.car.hardware.property.LaneCenteringAssistCommand} are supported.','google',1,'LaneCenteringAssistCommand',0,'2024-11-13 17:14:33','',0),(215,289411084,'LANE_CENTERING_ASSIST_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','车道中心辅助（LCA）州。\r\n<p>返回LCA的当前状态。此属性将始终返回有效的状态定义\r\n在{@link android.car.hardware.property.lanecenteringassstate}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果LCA包括车道出发警告，这些警告将通过车道浮出水面\r\n出发警告（LDW）属性。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.lanecenteringAssstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Lane Centering Assist (LCA) state.\r\n<p>Returns the current state of LCA. This property will always return a valid state defined\r\nin {@link android.car.hardware.property.LaneCenteringAssistState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If LCA includes lane departure warnings, those warnings will be surfaced through the Lane\r\nDeparture Warning (LDW) properties.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.LaneCenteringAssistState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'LaneCenteringAssistState|ErrorState',0,'2024-11-13 17:14:33','',0),(216,287313933,'EMERGENCY_LANE_KEEP_ASSIST_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用紧急车道助攻（ELKA）。\r\n<p>如果启用ELKA，则返回true，如果禁用Elka，则false。启用Elka时\r\n车辆中的ADAS系统应打开并监视驾驶员不安全的车道更换。\r\n当检测到不安全的操作时，Elka警告驾驶员并应用转向更正\r\n将车辆保持在原始车道上。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Emergency Lane Keep Assist (ELKA).\r\n<p>Return true if ELKA is enabled and false if ELKA is disabled. When ELKA is enabled, the\r\nADAS system in the vehicle should be on and monitoring for unsafe lane changes by the driver.\r\nWhen an unsafe maneuver is detected, ELKA alerts the driver and applies steering corrections\r\nto keep the vehicle in its original lane.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(217,289411086,'EMERGENCY_LANE_KEEP_ASSIST_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','紧急巷道辅助（ELKA）州。\r\n<p>返回ELKA的当前状态。通常，此属性应返回有效的状态\r\n在{@link android.car.hardware.property.emergencylanekeepassiststate}或{@link中定义\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.emergencylanekeepassistState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Emergency Lane Keep Assist (ELKA) state.\r\n<p>Returns the current state of ELKA. Generally, this property should return a valid state\r\ndefined in the {@link android.car.hardware.property.EmergencyLaneKeepAssistState} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.EmergencyLaneKeepAssistState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'EmergencyLaneKeepAssistState|ErrorState',0,'2024-11-13 17:14:33','',0),(218,287313935,'CRUISE_CONTROL_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用巡航控制（CC）。\r\n<p>如果启用了CC，则返回true，如果禁用了CC，则false。此属性由所有人共享\r\n{@link android.car.hardware.property.cruisecontroltype}的形式。\r\n<p>启用CC时，应打开车辆中的ADAS系统并响应\r\n命令。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Cruise Control (CC).\r\n<p>Return true if CC is enabled and false if CC is disabled. This property is shared by all\r\nforms of {@link android.car.hardware.property.CruiseControlType}).\r\n<p>When CC is enabled, the ADAS system in the vehicle should be turned on and responding to\r\ncommands.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(219,289411088,'CRUISE_CONTROL_TYPE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','当前的巡航控制类型（CC）。\r\n<p>当{@link #cruise_control_enabled}为true时，此属性返回CC的类型\r\n当前启用（例如，标准CC，自适应CC等）。通常，此属性\r\n应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.cruisecontroltype}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.cruisecontroltype} and {@link\r\n支持Android.car.hardware.property.errorstate}。\r\n尝试编写{@link android.car.hardware.property.cruisecontroltype＃其他}或一个\r\n{@link android.car.hardware.property.errstate}到此属性将抛出{@code\r\nIllegalArgumentException}。','Current type of Cruise Control (CC).\r\n<p>When {@link #CRUISE_CONTROL_ENABLED} is true, this property returns the type of CC that is\r\ncurrently enabled (for example, standard CC, adaptive CC, etc.). Generally, this property\r\nshould return a valid state defined in the {@link\r\nandroid.car.hardware.property.CruiseControlType} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.CruiseControlType} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.\r\nTrying to write {@link android.car.hardware.property.CruiseControlType#OTHER} or an\r\n{@link android.car.hardware.property.ErrorState} to this property will throw an {@code\r\nIllegalArgumentException}.','google',1,'CruiseControlType|ErrorState',0,'2024-11-13 17:14:33','',0),(220,289411089,'CRUISE_CONTROL_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','当前巡航控制状态（CC）。\r\n<p>此属性返回CC的状态。通常，此属性应返回有效\r\n在{@link android.car.hardware.property.cruisecontrolstate}或{@link中定义的状态\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.cruisecontrolstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Current state of Cruise Control (CC).\r\n<p>This property returns the state of CC. Generally, this property should return a valid\r\nstate defined in the {@link android.car.hardware.property.CruiseControlState} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.CruiseControlState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'CruiseControlState|ErrorState',0,'2024-11-13 17:14:33','',0),(221,289411090,'CRUISE_CONTROL_COMMAND','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','写巡航控制（CC）命令。\r\n<p>请参阅{@link android.car.hardware.property.cruisecontrolcommand}有关\r\n每个支持的命令。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n支持{@link android.car.hardware.property.cruisecontrolcommand}。\r\n<p>当此属性不可用时（例如，{@link #cruise_control_enabled}是\r\nfalse），编写此属性会抛出{@link\r\nandroid.car.hardware.property.propertynotavailableException}。','Write Cruise Control (CC) commands.\r\n<p>See {@link android.car.hardware.property.CruiseControlCommand} for the details about\r\neach supported command.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.CruiseControlCommand} are supported.\r\n<p>When this property is unavailable (for example when {@link #CRUISE_CONTROL_ENABLED} is\r\nfalse), writing this property will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.','google',1,'CruiseControlCommand',0,'2024-11-13 17:14:33','',0),(222,291508243,'CRUISE_CONTROL_TARGET_SPEED','VEHICLE_AREA_TYPE_GLOBAL','Float','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','巡航控制的当前目标速度（CC）以每秒米为单位。\r\n<p> {@link android.car.hardware.property.areaidconfig＃getminvalue（）}} and {@link\r\nandroid.car.hardware.property.areaidconfig＃getmaxvalue（）}返回最小目标和最大目标\r\n速度值分别。这些值将是非负的。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getminvalue（）}表示较低\r\n目标速度的界限。\r\n<p> {@link android.car.hardware.property.areaidConfig＃getmaxvalue（）}代表上层\r\n目标速度的界限。\r\n<p>当此属性不可用时（例如，{@link #cruise_control_enabled}是\r\nfalse），阅读此属性会抛出{@link\r\nandroid.car.hardware.property.propertynotavailableException}。','Current target speed for Cruise Control (CC) in meters per second.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} and {@link\r\nandroid.car.hardware.property.AreaIdConfig#getMaxValue()} return the min and max target\r\nspeed values respectively. These values will be non-negative.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMinValue()} represents the lower\r\nbound of the target speed.\r\n<p>{@link android.car.hardware.property.AreaIdConfig#getMaxValue()} represents the upper\r\nbound of the target speed.\r\n<p>When this property is unavailable (for example when {@link #CRUISE_CONTROL_ENABLED} is\r\nfalse), reading this property will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.','google',1,'',0,'2024-11-13 17:14:33','',0),(223,289411092,'ADAPTIVE_CRUISE_CONTROL_TARGET_TIME_GAP','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','自适应巡航控制（ACC）或预测巡航控制的当前目标时间差距\r\n毫秒。\r\n<p>此属性应指定领先车辆的目标时间差距。这个差距是定义的\r\n随着领先车辆最后方点之间的距离到达ACC的时间\r\n车辆的最高点。领先车辆的实际时间差距可以高于或以上\r\n这个值。\r\n<p>应在{@code中指定目标时间差距设置的可能值\r\n配置}按顺序排列。所有值必须为正。如果财产是可写的，\r\n所有价值都必须是可写的。\r\n<p>当此属性不可用时（例如，{@link #cruise_control_enabled}是\r\nfalse），阅读或写入此属性会抛出{@link\r\nandroid.car.hardware.property.propertynotavailableException}。','Current target time gap for Adaptive Cruise Control (ACC) or Predictive Cruise Control in\r\nmilliseconds.\r\n<p>This property should specify the target time gap to a leading vehicle. This gap is defined\r\nas the time to travel the distance between the leading vehicle\'s rear-most point to the ACC\r\nvehicle\'s front-most point. The actual time gap from a leading vehicle can be above or below\r\nthis value.\r\n<p>The possible values to set for the target time gap should be specified in {@code\r\nconfigArray} in ascending order. All values must be positive. If the property is writable,\r\nall values must be writable.\r\n<p>When this property is unavailable (for example when {@link #CRUISE_CONTROL_ENABLED} is\r\nfalse), reading or writing this property will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.','google',1,'',0,'2024-11-13 17:14:33','',0),(224,289411093,'ADAPTIVE_CRUISE_CONTROL_LEAD_VEHICLE_MEASURED_DISTANCE','VEHICLE_AREA_TYPE_GLOBAL','Integer','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_CONTINUOUS','使用自适应巡航控制（ACC）或预测性时，距离领先车辆的距离\r\n以毫米为单位的巡航控制。\r\n<p>返回距离领先车辆的米距离的距离\r\n领先车辆的最后方和ACC车辆的前排点。\r\n<p> {@link carpropertyConfig＃getminvalue（int）}返回0。\r\n<p> {@link carpropertyconfig＃getmaxvalue（int）}返回最大范围距离传感器\r\n可以支持。该值将是非负的。\r\n<p>当未检测到铅车时（即，当没有铅车或领先的车辆时\r\n车辆太远了，无法检测到传感器），此属性将抛出{@link\r\nandroid.car.hardware.property.propertynotavailableException}。\r\n<p>当此属性不可用时（例如，{@link #cruise_control_enabled}是\r\nfalse），阅读此属性会抛出{@link\r\nandroid.car.hardware.property.propertynotavailableException}。','Measured distance from leading vehicle when using Adaptive Cruise Control (ACC) or Predictive\r\nCruise Control in millimeters.\r\n<p>Returns the measured distance in meters from the lead vehicle for ACC between the\r\nrear-most point of the leading vehicle and the front-most point of the ACC vehicle.\r\n<p>{@link CarPropertyConfig#getMinValue(int)} returns 0.\r\n<p>{@link CarPropertyConfig#getMaxValue(int)} returns the maximum range the distance sensor\r\ncan support. This value will be non-negative.\r\n<p>When no lead vehicle is detected (that is, when there is no leading vehicle or the leading\r\nvehicle is too far away for the sensor to detect), this property will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.\r\n<p>When this property is unavailable (for example when {@link #CRUISE_CONTROL_ENABLED} is\r\nfalse), reading this property will throw a {@link\r\nandroid.car.hardware.property.PropertyNotAvailableException}.','google',1,'',0,'2024-11-13 17:14:33','',0),(225,287313942,'HANDS_ON_DETECTION_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用检测手（HOD）。\r\n<p>如果启用了HOD，则返回true，如果禁用了HOD，则false。启用HOD时，系统\r\n车内应监视驾驶员的手在转向上的存在\r\n车轮并发出警告，如果检测到驾驶员的手不再在转向上\r\n车轮。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Hands On Detection (HOD).\r\n<p>Return true if HOD is enabled and false if HOD is disabled. When HOD is enabled, a system\r\ninside the vehicle should be monitoring the presence of the driver\'s hands on the steering\r\nwheel and send a warning if it detects that the driver\'s hands are no longer on the steering\r\nwheel.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(226,289411095,'HANDS_ON_DETECTION_DRIVER_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','动手检测（HOD）驾驶员状态。\r\n<p>返回驾驶员的手是否在方向盘上。通常，此属性\r\n应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.handsondetectiondriverstate}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果车辆向用户发出警告，因为驾驶员的手已经关闭\r\n方向盘持续时间太长，警告应浮出水面\r\n{@link #hands_on_detection_warning}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.handsondetectiondriverstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Hands On Detection (HOD) driver state.\r\n<p>Returns whether the driver\'s hands are on the steering wheel. Generally, this property\r\nshould return a valid state defined in the {@link\r\nandroid.car.hardware.property.HandsOnDetectionDriverState} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If the vehicle is sending a warning to the user because the driver\'s hands have been off\r\nthe steering wheel for too long, the warning should be surfaced through\r\n{@link #HANDS_ON_DETECTION_WARNING}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.HandsOnDetectionDriverState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'HandsOnDetectionDriverState|ErrorState',0,'2024-11-13 17:14:33','',0),(227,289411096,'HANDS_ON_DETECTION_WARNING','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','动手检测（HOD）警告。\r\n<p>返回是否将警告发送给驾驶员，因为他们的双手脱离方向盘\r\n持续时间太长。\r\n<p>通常，此属性应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.handsondetectionwarning}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，该信息应通过{@link传达\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.handsondetectionwarning} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Hands On Detection (HOD) warning.\r\n<p>Returns whether a warning is being sent to the driver for having their hands off the wheel\r\nfor too long a duration.\r\n<p>Generally, this property should return a valid state defined in the {@link\r\nandroid.car.hardware.property.HandsOnDetectionWarning} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through an {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.HandsOnDetectionWarning} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'HandsOnDetectionWarning|ErrorState',0,'2024-11-13 17:14:33','',0),(228,287313945,'DRIVER_DROWSINESS_ATTENTION_SYSTEM_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用驾驶员嗜睡和注意力监测。\r\n<p>设置为实现驾驶员嗜睡和注意监控的真实设置，而虚假以禁用驱动程序\r\n嗜睡和注意力监测。当驾驶员昏昏欲睡和注意力监测时\r\n已启用，车辆内部的系统将监视嗜睡和注意力水平\r\n驾驶员并在需要时警告驾驶员。','Enable or disable driver drowsiness and attention monitoring.\r\n<p>Set true to enable driver drowsiness and attention monitoring and false to disable driver\r\ndrowsiness and attention monitoring. When driver drowsiness and attention monitoring is\r\nenabled, a system inside the vehicle will monitor the drowsiness and attention level of the\r\ndriver and warn the driver if needed.','google',1,'',0,'2024-11-13 17:14:33','',0),(229,289411098,'DRIVER_DROWSINESS_ATTENTION_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','驾驶员嗜睡和注意力水平状态。\r\n<p>根据\r\nKarolinska嗜睡量表（KSS）。\r\n<p>通常，此属性应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.driverdrowsinessattentionState}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果车辆正在向用户发出警告，因为驾驶员太昏昏欲睡了，\r\n警告应通过{@link #driver_drowsiness_attention_warning}浮出水面。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.driverdrowsinessattentionState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Driver drowsiness and attention level state.\r\n<p>Returns the current detected state of driver drowiness and attention level based on the\r\nKarolinska Sleepiness Scale (KSS).\r\n<p>Generally, this property should return a valid state defined in the {@link\r\nandroid.car.hardware.property.DriverDrowsinessAttentionState} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If the vehicle is sending a warning to the user because the driver is too drowsy, the\r\nwarning should be surfaced through {@link #DRIVER_DROWSINESS_ATTENTION_WARNING}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.DriverDrowsinessAttentionState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'DriverDrowsinessAttentionState|ErrorState',0,'2024-11-13 17:14:33','',0),(230,287313947,'DRIVER_DROWSINESS_ATTENTION_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用驾驶员嗜睡和注意力警告。\r\n<p>设置为实现驾驶员嗜睡和注意警告的真实性，并虚假禁用驱动程序\r\n嗜睡和注意力警告。当启用驾驶员嗜睡和注意警告时\r\n车辆内部的驾驶员嗜睡和注意监测系统应警告\r\n当驾驶员发现驾驶员昏昏欲睡或不专心时。','Enable or disable driver drowsiness and attention warnings.\r\n<p>Set true to enable driver drowsiness and attention warnings and false to disable driver\r\ndrowsiness and attention warnings. When driver drowsiness and attention warnings are enabled,\r\nthe driver drowsiness and attention monitoring system inside the vehicle should warn the\r\ndriver when it detects the driver is drowsy or not attentive.','google',1,'',0,'2024-11-13 17:14:33','',0),(231,289411100,'DRIVER_DROWSINESS_ATTENTION_WARNING','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','驾驶员昏昏欲睡和注意力警告。\r\n<p>返回是否正在向驾驶员发出警告，以免昏昏欲睡。\r\n<p>通常，此属性应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.driverdrowsinessattentionwarning}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，该信息应通过{@link传达\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.driverdrowsinessattentionwarning} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Driver drowsiness and attention warning.\r\n<p>Returns whether a warning is being sent to the driver for being drowsy or not attentive.\r\n<p>Generally, this property should return a valid state defined in the {@link\r\nandroid.car.hardware.property.DriverDrowsinessAttentionWarning} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through an {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.DriverDrowsinessAttentionWarning} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'DriverDrowsinessAttentionWarning|ErrorState',0,'2024-11-13 17:14:33','',0),(232,287313949,'DRIVER_DISTRACTION_SYSTEM_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用驾驶员分心监视。\r\n<p>设置为实现驾驶员分心监测的态度，而虚假以使驾驶员分散注意力\r\n监视。启用驾驶员分心监测后，车辆内部的系统应\r\n监视驾驶员的干扰水平，并在需要时警告驾驶员。','Enable or disable driver distraction monitoring.\r\n<p>Set true to enable driver distraction monitoring and false to disable driver distraction\r\nmonitoring. When driver distraction monitoring is enabled, a system inside the vehicle should\r\nbe monitoring the distraction level of the driver and warn the driver if needed.','google',1,'',0,'2024-11-13 17:14:33','',0),(233,289411102,'DRIVER_DISTRACTION_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','驾驶员分心状态。\r\n<p>返回当前检测到的驾驶员分心状态。\r\n<p>通常，此属性应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.driverdistractionState}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，应通过{@link传达该信息\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果车辆正在向用户发出警告，因为驾驶员太分心了，\r\n警告应通过{@link #driver_distraction_warning}浮出水面。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.driverdistractionState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Driver distraction state.\r\n<p>Returns the current detected driver distraction state.\r\n<p>Generally, this property should return a valid state defined in the {@link\r\nandroid.car.hardware.property.DriverDistractionState} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If the vehicle is sending a warning to the user because the driver is too distracted, the\r\nwarning should be surfaced through {@link #DRIVER_DISTRACTION_WARNING}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.DriverDistractionState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'DriverDistractionState|ErrorState',0,'2024-11-13 17:14:33','',0),(234,287313951,'DRIVER_DISTRACTION_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用驾驶员分心警告。\r\n<p>设置为启用驾驶员分心警告的真实和虚假以使驾驶员分心\r\n警告。启用驾驶员分心警告后，驾驶员分心监视\r\n车辆内部的系统应警告驾驶员发现驾驶员分心时。','Enable or disable driver distraction warnings.\r\n<p>Set true to enable driver distraction warnings and false to disable driver distraction\r\nwarnings. When driver distraction warnings are enabled, the driver distraction monitoring\r\nsystem inside the vehicle should warn the driver when it detects the driver is distracted.','google',1,'',0,'2024-11-13 17:14:33','',0),(235,289411104,'DRIVER_DISTRACTION_WARNING','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','驾驶员分心警告。\r\n<p>返回是否正在向驾驶员发出警告。\r\n<p>通常，此属性应返回{@link中定义的有效状态\r\nandroid.car.hardware.property.driverDistractionWarning}或{@link\r\nandroid.car.hardware.property.errorstate}。例如，如果该功能不可用\r\n在某种临时状态下，该信息应通过{@link传达\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.driverdistractionWarning} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Driver distraction warning.\r\n<p>Returns whether a warning is being sent to the driver for being distracted.\r\n<p>Generally, this property should return a valid state defined in the {@link\r\nandroid.car.hardware.property.DriverDistractionWarning} or {@link\r\nandroid.car.hardware.property.ErrorState}. For example, if the feature is not available due\r\nto some temporary state, that information should be conveyed through an {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.DriverDistractionWarning} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'DriverDistractionWarning|ErrorState',0,'2024-11-13 17:14:33','',0),(236,287313953,'LOW_SPEED_COLLISION_WARNING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用低速碰撞警告。\r\n<p>如果启用了低速碰撞警告，则返回true，如果低速碰撞，则返回\r\n警告被禁用。当启用低速碰撞警告时，ADAS系统在\r\n车辆会以低速警告驾驶员潜在的碰撞。这个属性是\r\n与预先存在的{@link wareperpropertyids＃forward_collision_warning_enabled}不同不同\r\n仅适用于更高速度应用。如果车辆没有单独\r\n低速环境的碰撞检测系统将无法实现此属性。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Low Speed Collision Warning.\r\n<p>Returns true if low speed collision warning is enabled and false if low speed collision\r\nwarning is disabled. When low speed collision warning is enabled, the ADAS system in the\r\nvehicle will warn the driver of potential collisions at low speeds. This property is\r\ndifferent from the pre-existing {@link VehiclePropertyIds#FORWARD_COLLISION_WARNING_ENABLED},\r\nwhich applies to higher speed applications only. If the vehicle doesn\'t have a separate\r\ncollision detection system for low speed environments, this property will not be implemented.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(237,289411106,'LOW_SPEED_COLLISION_WARNING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','低速碰撞警告州状态。\r\n<p>返回低速碰撞警告的当前状态。此属性将始终返回\r\n{@link android.car.hardware.property.lowspeedCollisionWarningState}中定义的有效状态\r\n或{@link android.car.hardware.property.errstate}。此属性与\r\n预先存在{@link parterpropertyids＃forward_collision_warning_enabled}，适用于\r\n仅更高的速度应用。如果车辆没有单独的碰撞检测\r\n对于低速环境的系统，将无法实现此属性。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.lowspeedCollisionWarningState} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Low Speed Collision Warning State state.\r\n<p>Returns the current state of Low Speed Collision Warning. This property will always return\r\na valid state defined in {@link android.car.hardware.property.LowSpeedCollisionWarningState}\r\nor {@link android.car.hardware.property.ErrorState}. This property is different from the\r\npre-existing {@link VehiclePropertyIds#FORWARD_COLLISION_WARNING_ENABLED}, which applies to\r\nhigher speed applications only. If the vehicle doesn\'t have a separate collision detection\r\nsystem for low speed environments, this property will not be implemented.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.LowSpeedCollisionWarningState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'android.car.hardware.property.LowSpeedCollisionWarningState|ErrorState',0,'2024-11-13 17:14:33','',0),(238,287313955,'CROSS_TRAFFIC_MONITORING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用交叉流量监控。\r\n<p>如果启用了交叉流量监控，则返回true\r\n被禁用。启用交叉交通监控后，车辆中的ADAS系统应\r\n打开并监视潜在的侧面碰撞。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Cross Traffic Monitoring.\r\n<p>Returns true if Cross Traffic Monitoring is enabled and false if Cross Traffic Monitoring\r\nis disabled. When Cross Traffic Monitoring is enabled, the ADAS system in the vehicle should\r\nbe turned on and monitoring for potential sideways collisions.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(239,289411108,'CROSS_TRAFFIC_MONITORING_WARNING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','交叉交通监控警告状态。\r\n<p>返回跨流量监控警告的当前状态。这个属性将永远\r\n返回{@link中定义的有效状态\r\nandroid.car.hardware.property.CrosstrafficMonoringWarningState}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.crosstrafficmonitoringwarningstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Cross Traffic Monitoring Warning state.\r\n<p>Returns the current state of Cross Traffic Monitoring Warning. This property will always\r\nreturn a valid state defined in {@link\r\nandroid.car.hardware.property.CrossTrafficMonitoringWarningState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.CrossTrafficMonitoringWarningState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'android.car.hardware.property.CrossTrafficMonitoringWarningState|ErrorState',0,'2024-11-13 17:14:33','',0),(240,287313957,'LOW_SPEED_AUTOMATIC_EMERGENCY_BRAKING_ENABLED','VEHICLE_AREA_TYPE_GLOBAL','Boolean','AAOS','VEHICLE_PROPERTY_ACCESS_READ_WRITE','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','启用或禁用低速自动紧急制动。\r\n<p>如果启用了低速自动紧急制动或假，则返回true\r\n自动紧急制动是禁用的。当低速自动紧急制动是\r\n已启用，将打开车辆中的ADAS系统并进行监视以避免潜在\r\n在低速条件下发生碰撞。该属性与先前的\r\nautomatic_emergency_braking_enabled，仅适用于更高速度应用程序。如果\r\n该车辆没有针对低速环境的单独避免碰撞系统，\r\n该属性将不会实施。\r\n<p>此属性定义为read_write，但是OEM可以选择以读取\r\n仅有的。','Enable or disable Low Speed Automatic Emergency Braking.\r\n<p>Returns true if Low Speed Automatic Emergency Braking is enabled or false if Low Speed\r\nAutomatic Emergency Braking is disabled. When Low Speed Automatic Emergency Braking is\r\nenabled, the ADAS system in the vehicle will be turned on and monitoring to avoid potential\r\ncollisions in low speed conditions. This property is different from the pre-existing\r\nAUTOMATIC_EMERGENCY_BRAKING_ENABLED, which should apply to higher speed applications only. If\r\nthe vehicle doesn\'t have a separate collision avoidance system for low speed environments,\r\nthis property will not be implemented.\r\n<p>This property is defined as read_write, but OEMs have the option to implement it as read\r\nonly.','google',1,'',0,'2024-11-13 17:14:33','',0),(241,289411110,'LOW_SPEED_AUTOMATIC_EMERGENCY_BRAKING_STATE','VEHICLE_AREA_TYPE_GLOBAL','Enum','AAOS','VEHICLE_PROPERTY_ACCESS_READ','VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE','低速自动紧急制动状态。\r\n<p>返回低速自动紧急制动的当前状态。该属性将\r\n始终返回{@link中定义的有效状态\r\nandroid.car.hardware.property.lowspeedautomaticemergencybrakingstate}或{@link\r\nandroid.car.hardware.property.errorstate}。\r\n<p>如果低速自动紧急制动包括在激活之前的碰撞警告\r\n刹车，这些警告将通过{@link使用{\r\nandroid.car.vehiclepropertyids＃low_speed_collision_warning_enabled}和{@link\r\nandroid.car.vehiclepropertyids＃low_speed_collision_warning_state}。\r\n<p>对于全球区域ID（0），{@link\r\nandroid.car.hardware.property.areaidconfig＃getSupportedEnumvalues（）}从\r\n{@link android.car.hardware.carpropertyconfig＃getareAidConfig（int）}指定哪个指示\r\n来自{@link android.car.hardware.property.lowspeedautomaticemergencybrakingstate} and {@link\r\n支持Android.car.hardware.property.errorstate}。','Low Speed Automatic Emergency Braking state.\r\n<p>Returns the current state of Low Speed Automatic Emergency Braking. This property will\r\nalways return a valid state defined in {@link\r\nandroid.car.hardware.property.LowSpeedAutomaticEmergencyBrakingState} or {@link\r\nandroid.car.hardware.property.ErrorState}.\r\n<p>If Low Speed Automatic Emergency Braking includes collision warnings before activating the\r\nbrakes, those warnings will be surfaced through use of {@link\r\nandroid.car.VehiclePropertyIds#LOW_SPEED_COLLISION_WARNING_ENABLED} and {@link\r\nandroid.car.VehiclePropertyIds#LOW_SPEED_COLLISION_WARNING_STATE}.\r\n<p>For the global area ID (0), the {@link\r\nandroid.car.hardware.property.AreaIdConfig#getSupportedEnumValues()} array obtained from\r\n{@link android.car.hardware.CarPropertyConfig#getAreaIdConfig(int)} specifies which states\r\nfrom {@link android.car.hardware.property.LowSpeedAutomaticEmergencyBrakingState} and {@link\r\nandroid.car.hardware.property.ErrorState} are supported.','google',1,'android.car.hardware.property.LowSpeedAutomaticEmergencyBrakingState|ErrorState',0,'2024-11-13 17:14:33','',0);
