INSERT INTO `mark_exportable` VALUES ('REMAINING_POWER_DISPLAY_MODE',146176,'feng.deliang@qq.com','{\"intId\":571,\"intValue\":146176,\"id\":\"REMAINING_POWER_DISPLAY_MODE\",\"vehicleAreaType\":\"VEHICLE_AREA_TYPE_GLOBAL\",\"project\":{\"id\":17,\"name\":\"hongqi\",\"remark\":\"红旗\",\"author\":\"deliang.feng@ecarxgroup.com\"},\"propertyType\":\"Enum\",\"module\":\"IHUD\",\"accessType\":\"VEHICLE_PROPERTY_ACCESS_READ_WRITE\",\"changeMode\":\"VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE\",\"chineseComment\":\"HUD上对剩余电量的显示模式\",\"englishComment\":\"remaining power display mode on hud\",\"author\":\"feng.deliang@qq.com\",\"published\":false,\"exportable\":true,\"propertyValue\":\"PowerDisplayMode\",\"createTime\":\"2024-09-10 19:26:37\",\"subItems\":[{\"module\":\"IHUD\",\"name\":\"PowerDisplayMode\",\"enumItem\":\"PERCENTAGE\",\"itemValue\":1,\"comment\":\"剩余电量百分比\",\"author\":\"feng.deliang@qq.com\",\"published\":false},{\"module\":\"IHUD\",\"name\":\"PowerDisplayMode\",\"enumItem\":\"ENDURANCE\",\"itemValue\":2,\"comment\":\"可续航里程\",\"author\":\"feng.deliang@qq.com\",\"published\":false}],\"oldEnumValue\":{\"module\":\"\",\"name\":\"\",\"subItems\":null}}','2024-09-11 10:00:00'),('HVAC_FAULT_NOTIFY',149504,'jian2.min@ecarxgroup.com','{\"intId\":584,\"intValue\":149504,\"id\":\"HVAC_FAULT_NOTIFY\",\"vehicleAreaType\":\"VEHICLE_AREA_TYPE_SEAT\",\"project\":{\"id\":16,\"name\":\"v446k\",\"remark\":\"woer\",\"author\":\"deliang.feng@ecarxgroup.com\"},\"propertyType\":\"Enum\",\"module\":\"IHvac\",\"accessType\":\"VEHICLE_PROPERTY_ACCESS_WRITE\",\"changeMode\":\"VEHICLE_PROPERTY_CHANGE_MODE_ONCHANGE\",\"chineseComment\":\"空调相关功能不可用情况下，用户点击时进行弹窗提醒。例如座椅通风、加热、方向盘加热等。原DX接口HVAC_FUNC_HEAT_VENTILATION_POP\",\"englishComment\":\"When the air conditioning related functions are not available, a pop-up window will be displayed when the user clicks. For example, seat ventilation, heating, steering wheel heating, etc. Original DX interface HVAC_FUNC_HEAT_VENTILATION_POP\",\"author\":\"jian2.m